function hfmV87PlayerFitness(player) {
  const value = Number(player?.fitness);
  return Number.isFinite(value) ? Math.round(value) : 100;
}
function hfmV87PlayerForm(player) {
  if (player?.form) return player.form;
  const hist = Array.isArray(player?.matchRatingHistory) ? player.matchRatingHistory.slice(-3) : [];
  if (!hist.length) return 'Normal';
  const avg = hist.reduce((a,b)=>a+Number(b || 0),0) / hist.length;
  if (avg <= 2.3) return 'Hoch';
  if (avg >= 3.8) return 'Tief';
  return 'Normal';
}
function hfmV87AvgNote(player) {
  if (Number(player?.seasonRatingGames || 0) > 0) return Math.round((Number(player.seasonRatingSum || 0) / Number(player.seasonRatingGames || 1)) * 10) / 10;
  const hist = Array.isArray(player?.matchRatingHistory) ? player.matchRatingHistory : [];
  if (!hist.length) return '-';
  return Math.round((hist.reduce((a,b)=>a+Number(b || 0),0) / hist.length) * 10) / 10;
}
function hfmV87ProfileHistory(player) {
  const hist = Array.isArray(player?.matchRatingHistory) ? player.matchRatingHistory.slice(-5) : [];
  const notes = hist.length ? hist.map(n => String(Number(n).toFixed(1)).replace('.', ',')).join(' · ') : 'Noch keine benoteten Spiele';
  const joined = player?.generatedSeason ? `Newgen seit ${player.generatedSeason}` : `Seit ${seasonLabel()} bei ${player?.club || ownClubName()}`;
  const goals = Number(player?.seasonGoals || 0);
  const assists = Number(player?.seasonAssists || 0);
  return `<div class="infoBox playerHistoryBox"><b>Historie</b><br>${joined}<br>Saison bisher: ${goals} Tore · ${assists} Vorlagen · Ø Note ${String(hfmV87AvgNote(player)).replace('.', ',')}<br>Letzte Noten: ${notes}</div>`;
}
