lineup = function() {
  const formationButtons = Object.keys(FORMATIONS).map(f => `<button class="chip ${state.formation === f ? 'selected' : ''}" onclick="setFormation('${f}')">${f}</button>`).join('');
  const markers = activePositions().map(slot => {
    const selectedId = state.lineup[slot.id];
    const selectedPlayer = state.players.find(p => p.id === Number(selectedId));
    const fit = positionFit(selectedPlayer, slot.pos);
    const eff = selectedPlayer ? effectiveStrength(selectedPlayer, slot.pos) : 0;
    const name = selectedPlayer ? selectedPlayer.name.split(' ').slice(-1)[0] : 'frei';
    const click = selectedPlayer ? `onclick="openOwnPlayerProfile(${selectedPlayer.id})"` : '';
    return `<button class="fieldPlayer draggablePlayer ${fit.className}" data-slot-id="${slot.id}" ${hfmV87DragAttrs('lineup', slot.id)} style="left:${slot.x}%; top:${slot.y}%;" ${click} aria-label="${slot.pos}: ${selectedPlayer ? selectedPlayer.name : 'frei'}"><span class="fieldPos">${slot.pos}</span><strong>${name}</strong><small>${selectedPlayer ? eff : '+'}</small></button>`;
  }).join('');
  return `<section class="panel"><p class="eyebrow">Team · Aufstellung</p><div class="chips">${formationButtons}</div><div class="lineupSummary"><span>Formation: <b>${state.formation}</b></span><span>Effektive Startelf Ø <b>${lineupStrength()}</b></span><span>Positionsprobleme: <b>${lineupPenaltyCount()}</b></span></div><div class="visualPitch freeFormationPitch" role="group" aria-label="Visuelle Aufstellung"><div class="pitchStripe one"></div><div class="pitchStripe two"></div><div class="pitchCenter"></div><div class="goal top"></div><div class="goal bottom"></div>${markers}</div>${hfmV89LineupRosterTable()}${playerProfileModal()}</section>`;
};

