/* Version 90: frei sortierbare Spalten in der Aufstellungsliste + robuste Spielerprofil-Buttons */
const HFM_V90_ROSTER_COLUMNS = [
  { id: 'number', label: '#', cell: (p, n, role, fit, sec) => String(n) },
  { id: 'status', label: 'St.', cell: (p, n, role, fit, sec) => `<b>${hfmV89RosterStatusShort(role.type)}</b>` },
  { id: 'pos', label: 'Pos.', cell: (p, n, role, fit, sec) => `<b>${role.pos}</b>` },
  { id: 'secondary', label: 'Nebenpos.', cell: (p, n, role, fit, sec) => sec || '-' },
  { id: 'name', label: 'Name', cell: (p) => `<strong>${p.name}</strong>` },
  { id: 'age', label: 'Alter', cell: (p) => String(Number(p.age || 0)) },
  { id: 'strength', label: 'Stärke', cell: (p, n, role, fit) => `<b>${fit}</b>` },
  { id: 'talent', label: 'Talent', cell: (p) => `<span class="stars">${stars(p.talent || 1)}</span>` },
  { id: 'moral', label: 'Moral', cell: (p) => String(Number(p.satisfaction || 60)) },
  { id: 'fitness', label: 'Fit.', cell: (p) => String(hfmV87PlayerFitness(p)) },
  { id: 'form', label: 'Form', cell: (p) => hfmV87PlayerForm(p) },
  { id: 'contract', label: 'Vertrag', cell: (p) => `${Number(p.contractYears || 0)} J.` },
  { id: 'marketValue', label: 'Marktwert', cell: (p) => euro(p.marketValue || 0) }
];
const HFM_V90_DEFAULT_ROSTER_ORDER = HFM_V90_ROSTER_COLUMNS.map(c => c.id);

function hfmV90ColumnMap() {
  return new Map(HFM_V90_ROSTER_COLUMNS.map(c => [c.id, c]));
}
function hfmV90EnsureRosterColumnOrder() {
  if (!Array.isArray(state.lineupRosterColumnOrder)) state.lineupRosterColumnOrder = HFM_V90_DEFAULT_ROSTER_ORDER.slice();
  const known = new Set(HFM_V90_DEFAULT_ROSTER_ORDER);
  state.lineupRosterColumnOrder = state.lineupRosterColumnOrder.filter(id => known.has(id));
  HFM_V90_DEFAULT_ROSTER_ORDER.forEach(id => { if (!state.lineupRosterColumnOrder.includes(id)) state.lineupRosterColumnOrder.push(id); });
}
function hfmV90MoveRosterColumn(fromId, toId) {
  hfmV90EnsureRosterColumnOrder();
  if (!fromId || !toId || fromId === toId) return false;
  const order = state.lineupRosterColumnOrder.slice();
  const fromIndex = order.indexOf(fromId);
  const toIndex = order.indexOf(toId);
  if (fromIndex < 0 || toIndex < 0) return false;
  const [item] = order.splice(fromIndex, 1);
  order.splice(toIndex, 0, item);
  state.lineupRosterColumnOrder = order;
  if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
  render();
  return true;
}
function hfmV90RosterColumnDragStart(event, id) {
  state.lineupRosterColumnDrag = id;
  if (event?.dataTransfer) {
    event.dataTransfer.setData('text/plain', id);
    event.dataTransfer.effectAllowed = 'move';
  }
}
function hfmV90RosterColumnDragOver(event) {
  if (event) event.preventDefault();
}
function hfmV90RosterColumnDrop(event, targetId) {
  if (event) {
    event.preventDefault();
    event.stopPropagation();
  }
  const sourceId = event?.dataTransfer?.getData('text/plain') || state.lineupRosterColumnDrag;
  state.lineupRosterColumnDrag = null;
  hfmV90MoveRosterColumn(sourceId, targetId);
  return false;
}
function hfmV90RosterHeaderPointerDown(event, id) {
  clearTimeout(state.lineupRosterColumnHoldTimer);
  state.lineupRosterColumnHold = { id, active: false, x: event?.clientX || 0, y: event?.clientY || 0 };
  state.lineupRosterColumnHoldTimer = setTimeout(() => {
    if (state.lineupRosterColumnHold && state.lineupRosterColumnHold.id === id) {
      state.lineupRosterColumnHold.active = true;
      const th = event?.currentTarget;
      if (th && th.classList) th.classList.add('columnHoldActive');
    }
  }, 420);
}
function hfmV90RosterHeaderPointerMove(event, id) {
  const hold = state.lineupRosterColumnHold;
  if (!hold || hold.id !== id) return;
  if (!hold.active && (Math.abs((event?.clientX || 0) - hold.x) > 10 || Math.abs((event?.clientY || 0) - hold.y) > 10)) {
    clearTimeout(state.lineupRosterColumnHoldTimer);
  }
}
function hfmV90RosterHeaderPointerEnd(event, id) {
  clearTimeout(state.lineupRosterColumnHoldTimer);
  const hold = state.lineupRosterColumnHold;
  const wasActive = hold && hold.id === id && hold.active;
  if (event?.currentTarget?.classList) event.currentTarget.classList.remove('columnHoldActive');
  state.lineupRosterColumnHold = null;
  if (!wasActive) return true;
  if (event) {
    event.preventDefault();
    event.stopPropagation();
  }
  const el = document.elementFromPoint(event.clientX, event.clientY);
  const target = el && el.closest ? el.closest('[data-roster-col]') : null;
  const targetId = target ? target.getAttribute('data-roster-col') : id;
  hfmV90MoveRosterColumn(id, targetId);
  return false;
}
function hfmV90RosterHeaderHtml() {
  hfmV90EnsureRosterColumnOrder();
  const cmap = hfmV90ColumnMap();
  return state.lineupRosterColumnOrder.map(id => {
    const col = cmap.get(id);
    if (!col) return '';
    const cls = id === 'status' ? 'statusShortHeader' : id === 'talent' ? 'talentHeader' : '';
    return `<th class="${cls}" data-roster-col="${id}" draggable="true" ondragstart="hfmV90RosterColumnDragStart(event,'${id}')" ondragover="hfmV90RosterColumnDragOver(event)" ondrop="return hfmV90RosterColumnDrop(event,'${id}')" onpointerdown="hfmV90RosterHeaderPointerDown(event,'${id}')" onpointermove="hfmV90RosterHeaderPointerMove(event,'${id}')" onpointerup="return hfmV90RosterHeaderPointerEnd(event,'${id}')" onpointercancel="return hfmV90RosterHeaderPointerEnd(event,'${id}')"><span>${col.label}</span></th>`;
  }).join('');
}
function hfmV90RosterRow(player, number) {
  hfmV90EnsureRosterColumnOrder();
  const role = hfmV87RosterRoleForPlayer(player);
  const sec = Array.isArray(player.secondary) ? player.secondary.join(' / ') : '';
  const fit = role.type === 'lineup' ? effectiveStrength(player, role.pos) : player.strength;
  const drag = hfmV87DragAttrs(role.type, role.slotId);
  const rowClass = role.type === 'lineup' ? 'starterRow' : role.type === 'bench' ? 'benchRow' : 'squadRow';
  const cmap = hfmV90ColumnMap();
  const cells = state.lineupRosterColumnOrder.map(id => {
    const col = cmap.get(id);
    if (!col) return '';
    const cls = id === 'status' ? 'statusShort' : id === 'talent' ? 'talentCell' : '';
    return `<td class="${cls}" data-roster-cell="${id}">${col.cell(player, number, role, fit, sec)}</td>`;
  }).join('');
  return `<tr class="rosterTableRow ${rowClass}" ${drag} onclick="return hfmV90OpenOwnPlayerProfile(event, ${player.id})">${cells}</tr>`;
}
function hfmV90LineupRosterTable() {
  const players = (state.players || []).filter(p => p.loan !== 'verliehen');
  const sorted = players.slice().sort((a,b) => {
    const ra = hfmV87RosterRoleForPlayer(a);
    const rb = hfmV87RosterRoleForPlayer(b);
    return ra.order - rb.order || ra.index - rb.index || Number(b.strength || 0) - Number(a.strength || 0);
  });
  const rows = sorted.map((p,i)=>hfmV90RosterRow(p, i + 1)).join('');
  return `<section class="rosterTablePanel"><h3>Kaderliste</h3><div class="miniHint">Spaltenkopf lange gedrückt halten und dann nach links oder rechts ziehen.</div><div class="tableWrap rosterTableWrap"><table class="rosterTable rosterTableV90"><thead><tr>${hfmV90RosterHeaderHtml()}</tr></thead><tbody>${rows}</tbody></table></div><div class="miniLegend"><span><b>SF</b> Startformation</span><span><b>B</b> Bank</span><span><b>T</b> Tribüne</span></div></section>`;
}
hfmV89RosterRow = hfmV90RosterRow;
hfmV89LineupRosterTable = hfmV90LineupRosterTable;
hfmV88RosterRow = hfmV90RosterRow;
hfmV88LineupRosterTable = hfmV90LineupRosterTable;

