playerProfileModal = function() {
  const p = state.playerProfile;
  if (!p) return '';
  const known = isPlayerKnown(p);
  const own = hfmV87IsOwnPlayer(p);
  const position = positionText(p);
  const valueCards = known ? `
    <article class="card"><p>Gesamtstärke</p><h2>${p.strength}</h2><span class="stars">${stars(p.talent)}</span></article>
    <article class="card"><p>Marktwert</p><h2>${euro(p.marketValue || 0)}</h2><span>ungefähre Kaderbewertung</span></article>
    <article class="card"><p>Vertrag</p><h2>${Number(p.contractYears || 0)} Jahre</h2><span>Gehalt ${euro(p.salary || 0)}</span></article>
    <article class="card"><p>Fitness / Form</p><h2>${hfmV87PlayerFitness(p)}% · ${hfmV87PlayerForm(p)}</h2><span>Moral ${Number(p.satisfaction || 60)}/100</span></article>
    <article class="card"><p>Rollenprofil</p><h2>Off ${playerUnitScore(p,'attack')} · Def ${playerUnitScore(p,'defense')}</h2><span>Technik ${playerUnitScore(p,'control')} · Flügel ${playerUnitScore(p,'wings')}</span></article>` : `
    <article class="card"><p>Gesamtstärke</p><h2>${p.strength}</h2><span>immer sichtbar</span></article>
    <article class="card"><p>Fähigkeiten</p><h2>?</h2><span>Scouting erforderlich</span></article>
    <article class="card"><p>Marktwert</p><h2>?</h2><span>Scouting erforderlich</span></article>
    <article class="card"><p>Vertrag</p><h2>?</h2><span>Scouting erforderlich</span></article>`;
  const actions = own ? `
    <button type="button" class="ghost full" onclick="return hfmV90OpenLineupFromProfile(event)">Zur Aufstellung</button>
    <button type="button" class="primary full" onclick="return hfmV90OpenContractsFromProfile(event)">Zur Vertragsansicht</button>` : (known ? `<button type="button" class="ghost full" ${watchlistHas(p.id) ? 'disabled' : ''} onclick="addToWatchlist('${p.id}', '${p.club}', ${p.leagueIndex})">${watchlistHas(p.id) ? 'Bereits auf Beobachtungsliste' : 'Auf Beobachtungsliste setzen'}</button><button type="button" class="primary full" onclick="makeContractOffer('${p.id}', '${p.club}', ${p.leagueIndex})">Vertragsangebot machen</button>` : `<button type="button" class="primary full" ${scoutingJobStatusText('player', { playerId: p.id }) ? 'disabled' : ''} onclick="scoutPlayer('${p.id}', '${p.club}', ${p.leagueIndex})">${scoutingJobStatusText('player', { playerId: p.id }) || `Spieler scouten · ${euro(scoutPlayerCost(p))}`}</button>`);
  return `<div class="lineupModalBackdrop" role="dialog" aria-modal="true"><div class="lineupModal playerProfileModal"><div class="modalHeader"><div><p class="eyebrow">Spielerprofil</p><h2>${p.name}</h2></div><button type="button" class="ghost closeButton" onclick="return closePlayerProfile(event)">Schließen</button></div><div class="grid compact"><article class="card"><p>Allgemein</p><h2>${position}</h2><span>${Number(p.age || 0)} Jahre · ${p.club || ownClubName()}</span></article>${valueCards}</div>${known ? skillBars(p) : ''}${hfmV87ProfileHistory(p)}${known ? '' : '<div class="infoBox">Dieser Spieler ist noch nicht gescoutet. Die Gesamtstärke ist bekannt, Details bleiben bis zum Scouting verborgen.</div>'}<div class="modalActions">${actions}</div></div></div>`;
};

