/* Version 96: Monatsboost mit gezielter Faehigkeitsauswahl im Training */
function hfmV96EnsureTrainingBoostSelections() {
  if (!state.trainingBoostSkillSelections || typeof state.trainingBoostSkillSelections !== 'object') state.trainingBoostSkillSelections = {};
}
function hfmV96PrimarySkillForPlayer(player) {
  const weights = POSITION_SKILL_WEIGHTS[player?.pos] || POSITION_SKILL_WEIGHTS.ZM || {};
  const sorted = Object.keys(weights).sort((a, b) => (weights[b] || 0) - (weights[a] || 0));
  return sorted[0] || PLAYER_SKILLS[0];
}
function hfmV96TrainingBoostSkill(playerId) {
  hfmV96EnsureTrainingBoostSelections();
  const player = state.players.find(p => Number(p.id) === Number(playerId));
  const selected = state.trainingBoostSkillSelections[playerId];
  if (selected && PLAYER_SKILLS.includes(selected)) return selected;
  return hfmV96PrimarySkillForPlayer(player);
}
function hfmV96TrainingBoostSkillOptions(player) {
  const selected = hfmV96TrainingBoostSkill(player.id);
  const weights = POSITION_SKILL_WEIGHTS[player.pos] || {};
  const ordered = [...PLAYER_SKILLS].sort((a, b) => (weights[b] || 0) - (weights[a] || 0) || String(SKILL_LABELS[a] || a).localeCompare(String(SKILL_LABELS[b] || b)));
  return ordered.map(skill => `<option value="${skill}" ${skill === selected ? 'selected' : ''}>${SKILL_LABELS[skill] || skill}${weights[skill] ? ' · wichtig' : ''}</option>`).join('');
}
function setTrainingBoostSkill(playerId, skill) {
  hfmV96EnsureTrainingBoostSelections();
  const id = Number(playerId);
  if (!PLAYER_SKILLS.includes(skill)) return false;
  state.trainingBoostSkillSelections[id] = skill;
  if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
  else if (typeof save === 'function') save();
  return false;
}
function hfmV96OpenTrainingPlayer(event, playerId) {
  if (event) {
    event.preventDefault();
    event.stopPropagation();
  }
  return openOwnPlayerProfile(playerId);
}
function hfmV96ApplySkillBoost(player, skill, gain = 0.7) {
  if (!player || !PLAYER_SKILLS.includes(skill)) return player;
  const skills = { ...(player.skills || generateSkillSet(player)) };
  const current = Number(skills[skill] ?? player.strength ?? 50);
  skills[skill] = clamp(Math.round((current + gain) * 10) / 10, 1, 100);
  const updated = { ...player, skills };
  return { ...updated, strength: positionOverall(updated, updated.pos) };
}
const hfmV96GiveTrainingBoostBase = giveTrainingBoost;
giveTrainingBoost = function(playerId, selectedSkill) {
  const player = state.players.find(p => Number(p.id) === Number(playerId));
  if (!player) return false;
  const skill = selectedSkill || hfmV96TrainingBoostSkill(player.id);
  if (!PLAYER_SKILLS.includes(skill)) {
    alert('Bitte zuerst eine Faehigkeit fuer den Monatsboost auswaehlen.');
    return false;
  }
  hfmV96EnsureTrainingBoostSelections();
  state.trainingBoostSkillSelections[player.id] = skill;
  const before = state.monthlyTrainingBoost ? { ...state.monthlyTrainingBoost } : null;
  const result = hfmV96GiveTrainingBoostBase(player.id);
  const active = state.monthlyTrainingBoost;
  if (active && Number(active.playerId) === Number(player.id) && active.monthKey === currentMonthKey()) {
    state.monthlyTrainingBoost = { ...active, skill };
    const idx = state.players.findIndex(p => Number(p.id) === Number(player.id));
    if (idx >= 0 && (!before || Number(before.playerId) !== Number(player.id) || before.monthKey !== active.monthKey)) {
      state.players[idx] = hfmV96ApplySkillBoost(state.players[idx], skill, 1);
    }
    if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
    render();
  }
  return result;
};
const hfmV96CalcDevelopmentBase = calcDevelopment;
calcDevelopment = function(player, focus) {
  const base = hfmV96CalcDevelopmentBase(player, focus);
  const boost = state.monthlyTrainingBoost;
  if (boost && Number(boost.playerId) === Number(player?.id) && boost.monthKey === currentMonthKey() && boost.skill) {
    return Math.round((base + 0.6) * 10) / 10;
  }
  return base;
};
const hfmV96NextWeekBase = nextWeek;
nextWeek = function() {
  const boost = state.monthlyTrainingBoost ? { ...state.monthlyTrainingBoost } : null;
  const beforeMonth = currentMonthKey();
  const result = hfmV96NextWeekBase();
  if (boost && boost.monthKey === beforeMonth && PLAYER_SKILLS.includes(boost.skill)) {
    const idx = state.players.findIndex(p => Number(p.id) === Number(boost.playerId));
    if (idx >= 0) {
      state.players[idx] = hfmV96ApplySkillBoost(state.players[idx], boost.skill, 0.6);
      if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
      render();
    }
  }
  return result;
};

/* Version 97: Trainingsziel-Prognose in Wochen */
function hfmV97TrainingTargetWeeks(player) {
  if (!player) return { weeks: null, text: 'Zielprognose nicht berechenbar' };
  const strength = Number(player.strength || 0);
  if (strength >= 100) return { weeks: 0, text: 'Trainingsziel erreicht · maximale Stärke' };
  const progress = clamp(Number(player.progress || 0), 0, 100);
  const gain = Number(calcDevelopment(player, state.trainingFocus) || 0);
  if (!Number.isFinite(gain) || gain <= 0) return { weeks: null, text: 'Trainingsziel derzeit nicht prognostizierbar' };
  const remaining = Math.max(0, 100 - progress);
  const weeks = Math.max(1, Math.ceil(remaining / gain));
  return { weeks, text: `Trainingsziel ca. in ${weeks} ${weeks === 1 ? 'Woche' : 'Wochen'}` };
}
training = function() {
  hfmV96EnsureTrainingBoostSelections();
  const dir = state.trainingSort || 'desc';
  const players = [...state.players].sort((a, b) => {
    const byProgress = (Number(a.progress || 0) - Number(b.progress || 0));
    return (dir === 'asc' ? byProgress : -byProgress) || Number(b.strength || 0) - Number(a.strength || 0);
  });
  const boostedId = boostedPlayerIdThisMonth();
  const boostInfo = boostedId ? state.players.find(p => Number(p.id) === Number(boostedId)) : null;
  const activeSkill = state.monthlyTrainingBoost && state.monthlyTrainingBoost.monthKey === currentMonthKey() ? state.monthlyTrainingBoost.skill : null;
  const list = players.map(player => {
    const isBoosted = Number(boostedId) === Number(player.id);
    const boostAvailable = !boostedId;
    const cost = trainingBoostCost(player);
    const selectedSkill = hfmV96TrainingBoostSkill(player.id);
    const selectedValue = Number((player.skills || {})[selectedSkill] ?? player.strength ?? 0);
    const boostSkillLine = isBoosted && activeSkill ? `<span>Boost-Faehigkeit: ${SKILL_LABELS[activeSkill] || activeSkill}</span>` : '';
    const skillSelect = boostAvailable ? `<label class="boostSkillSelect" onclick="event.stopPropagation()"><span>Monatsboost fuer</span><select onchange="return setTrainingBoostSkill(${player.id}, this.value)">${hfmV96TrainingBoostSkillOptions(player)}</select><small>Aktuell: ${SKILL_LABELS[selectedSkill] || selectedSkill} ${Math.round(selectedValue)}</small></label>` : '';
    return `<div class="player trainingPlayerCard">
      <div class="playerTop"><button type="button" class="inlineLink trainingPlayerName" onclick="return hfmV96OpenTrainingPlayer(event, ${player.id})"><strong>${player.name}</strong></button><span>${positionText(player)} · ${player.age} Jahre</span></div>
      <div class="meta"><span>Stärke ${player.strength}</span><span class="stars">${stars(player.talent)}</span><span>Trainingsfortschritt ${player.progress}%</span><span>Note ${Number(player.rating || 3).toFixed(1)}</span><span>${player.minutes || 0} Min.</span>${isBoosted ? '<span>Monatsboost aktiv</span>' : ''}${boostSkillLine}</div>
      <div class="bar"><div style="width:${clamp(Number(player.progress || 0), 0, 100)}%"></div></div>
      <div class="playerBottom"><span>${player.progress || 0}% bis Stärke ${Math.min(100, Number(player.strength || 0) + 1)}</span><span>voraussichtlich +${calcDevelopment(player, state.trainingFocus)}% Fortschritt pro Woche</span><span>${hfmV97TrainingTargetWeeks(player).text}</span></div>
      <div class="playerActions">${skillSelect}<button type="button" class="ghost" onclick="toggleLoan(${player.id})">${player.loan === 'verliehen' ? 'Leihe zurückholen' : 'Spieler verleihen'}</button><button type="button" class="primary" ${boostAvailable ? '' : 'disabled'} onclick="giveTrainingBoost(${player.id}, hfmV96TrainingBoostSkill(${player.id}))">Monatsboost · ${euro(cost)}</button></div>
    </div>`;
  }).join('');
  const boostText = boostInfo ? `<br><b>Aktueller Monatsboost:</b> ${boostInfo.name} · ${activeSkill ? (SKILL_LABELS[activeSkill] || activeSkill) : 'gewaehlte Faehigkeit'} bis Monatsende.` : '<br><b>Monatsboost:</b> Noch verfügbar. Waehle zuerst pro Spieler eine konkrete Faehigkeit und aktiviere danach den Boost.';
  return `<section class="panel"><div class="sectionHeader"><div><p class="eyebrow">Team · Training</p><h2>Trainingsübersicht</h2></div><select onchange="setTrainingSort(this.value)"><option value="desc" ${dir === 'desc' ? 'selected' : ''}>Fortschritt absteigend</option><option value="asc" ${dir === 'asc' ? 'selected' : ''}>Fortschritt aufsteigend</option></select></div><div class="infoBox">Spielernamen sind antippbar und öffnen direkt das Eigenschaftsfenster. Beim Monatsboost legst du jetzt vorher fest, welche konkrete Fähigkeit des Spielers gezielt verbessert werden soll.${boostText}</div><div class="playerList">${list}</div>${playerProfileModal()}</section>`;
};
try { render(); } catch (err) { console.error(err); }

