const HFM_V98_TRAIT_KEYS = Object.keys(HFM_V98_TRAITS);
function hfmV98TraitKey(player) {
  const key = String(player?.characterTrait || player?.trait || '').trim();
  return HFM_V98_TRAITS[key] ? key : 'BALANCED';
}
function hfmV98TraitDef(playerOrKey) {
  const key = typeof playerOrKey === 'string' ? playerOrKey : hfmV98TraitKey(playerOrKey);
  return HFM_V98_TRAITS[key] || HFM_V98_TRAITS.BALANCED;
}
function hfmV98TraitLabel(playerOrKey) { return hfmV98TraitDef(playerOrKey).label; }
function hfmV98TraitBadge(player, extraClass = '') {
  const key = hfmV98TraitKey(player);
  const def = hfmV98TraitDef(key);
  return `<span class="traitBadge trait-${def.badge} ${extraClass}" title="${hfmV68Html(def.short)}">${hfmV68Html(def.label)}</span>`;
}
function hfmV98WeightedTrait(player) {
  const pos = player?.pos || 'ZM';
  const age = Number(player?.age || 24);
  const talent = Number(player?.talent || 3);
  const weights = {
    BALANCED: 34, MODEL_PRO: 18, ALLROUNDER: 9, SHY: age <= 21 ? 12 : 5, AMBITIOUS: ['ST','LA','RA','OM'].includes(pos) ? 10 : 6,
    ROBUST: ['TW','IV','DM'].includes(pos) ? 7 : 4, FIGHTER: ['DM','IV','ZM'].includes(pos) ? 5 : 2, LEADER: ['TW','IV','DM'].includes(pos) && age >= 26 ? 3 : 1,
    ICE_COLD: ['TW','ST','OM'].includes(pos) ? 2.2 : 1, HOTHEAD: ['IV','DM','ST'].includes(pos) ? 3.2 : 1.6, WEAK_NERVES: age <= 22 ? 3.5 : 2,
    DIVA: ['ST','LA','RA','OM'].includes(pos) ? 2.4 : .8, MERCENARY: 1.6, LOYAL: 2.4, SELFISH: ['ST','LA','RA','OM'].includes(pos) ? 4.5 : 1.3,
    TEAM_PLAYER: ['ZM','OM','ST'].includes(pos) ? 4 : 2.5, INJURY_PRONE: 3.2, TRAINING_BEAST: 3.5, ETERNAL_TALENT: age <= 24 ? 2.8 : 1.2,
    SUPER_SUB: ['ST','LA','RA','OM'].includes(pos) ? 2.8 : 1.3, PARTY: age <= 27 ? 2.2 : 1.2, LAZY: talent >= 4 ? 2.8 : 1.4,
    EARLY_BLOOMER: age <= 23 ? 3.4 : .8, LATE_BLOOMER: age >= 23 ? 3.2 : 1.2
  };
  if (talent >= 5) { weights.DIVA *= 1.8; weights.ETERNAL_TALENT *= 2.1; weights.INJURY_PRONE *= 1.55; weights.LAZY *= 1.35; weights.MODEL_PRO *= .8; }
  if (talent <= 2) { weights.BALANCED *= 1.18; weights.MODEL_PRO *= 1.1; weights.DIVA *= .6; weights.ETERNAL_TALENT *= .5; }
  if (age >= 30) { weights.LEADER *= 1.6; weights.MODEL_PRO *= 1.15; weights.PARTY *= .65; weights.SHY *= .5; }
  const seed = Math.abs(stableHash(`${player?.id || ''}-${player?.name || ''}-${pos}-${age}-${talent}-trait-v98`));
  const entries = Object.entries(weights).filter(([key, value]) => HFM_V98_TRAITS[key] && value > 0);
  const total = entries.reduce((sum, [, value]) => sum + value, 0);
  let pick = (seed % 100000) / 100000 * total;
  for (const [key, value] of entries) { pick -= value; if (pick <= 0) return key; }
  return 'BALANCED';
}
function hfmV98EnsureCharacterTrait(player) {
  if (!player || typeof player !== 'object') return player;
  const current = String(player.characterTrait || player.trait || '').trim();
  const characterTrait = HFM_V98_TRAITS[current] ? current : hfmV98WeightedTrait(player);
  return { ...player, characterTrait };
}
function hfmV98EnsureAllCharacterTraits() {
  state.players = (state.players || []).map(hfmV98EnsureCharacterTrait);
  state.academyPlayers = (state.academyPlayers || []).map(hfmV98EnsureCharacterTrait);
  state.watchlist = (state.watchlist || []).map(hfmV98EnsureCharacterTrait);
  state.transferFreeAgents = (state.transferFreeAgents || []).map(hfmV98EnsureCharacterTrait);
  if (state.playerProfile) state.playerProfile = hfmV98EnsureCharacterTrait(state.playerProfile);
  if (state.clubRosterCache && typeof state.clubRosterCache === 'object') {
    Object.keys(state.clubRosterCache).forEach(key => { state.clubRosterCache[key] = (state.clubRosterCache[key] || []).map(hfmV98EnsureCharacterTrait); });
  }
}
const hfmV98EnsurePlayerSkillProfileBase = ensurePlayerSkillProfile;
