const hfmV98LoadGameBase = loadGame;
loadGame = function() { const result = hfmV98LoadGameBase(); hfmV98EnsureAllCharacterTraits(); return result; };

function hfmV98TrainingMultiplier(player) {
  const key = hfmV98TraitKey(player);
  let mult = Number(hfmV98TraitDef(key).training || 1);
  const age = Number(player?.age || 24);
  if (key === 'ETERNAL_TALENT' && age >= 23 && Number(player?.minutes || 0) < 31) mult *= 0.68;
  if (key === 'EARLY_BLOOMER') mult *= age <= 23 ? 1.12 : age >= 25 ? 0.78 : 1;
  if (key === 'LATE_BLOOMER') mult *= age >= 25 ? 1.28 : 0.82;
  if (key === 'SHY' && hfmV98TeamTraitCount(state.players, 'LEADER') > 0) mult *= 1.06;
  return mult;
}
function hfmV98TrainingEffectText(player) {
  const mult = hfmV98TrainingMultiplier(player);
  const pct = Math.round((mult - 1) * 100);
  if (pct === 0) return 'Training neutral';
  return `${pct > 0 ? '+' : ''}${pct}% Training durch Charakter`;
}
const hfmV98CalcDevelopmentBase = calcDevelopment;
calcDevelopment = function(player, focus) {
  const base = Number(hfmV98CalcDevelopmentBase(player, focus) || 0);
  return Math.max(0.1, Math.round(base * hfmV98TrainingMultiplier(player) * 10) / 10);
};
function hfmV98TeamTraitCount(players, key) { return (players || []).filter(p => hfmV98TraitKey(p) === key).length; }
function hfmV98TeamMatrix(players) {
  const list = players || [];
  const leaders = hfmV98TeamTraitCount(list, 'LEADER');
  const model = hfmV98TeamTraitCount(list, 'MODEL_PRO');
  const fighters = hfmV98TeamTraitCount(list, 'FIGHTER');
  const divas = hfmV98TeamTraitCount(list, 'DIVA');
  const mercs = hfmV98TeamTraitCount(list, 'MERCENARY');
  const hotheads = hfmV98TeamTraitCount(list, 'HOTHEAD');
  const shy = hfmV98TeamTraitCount(list, 'SHY');
  const frustrated = list.filter(p => Number(p.satisfaction || 60) < 45).length;
  let factor = 1 + Math.min(0.05, leaders * 0.012 + model * 0.005 + fighters * 0.006) - Math.min(0.08, divas * 0.018 + mercs * 0.012 + hotheads * 0.01 + frustrated * 0.006);
  if (shy && !leaders) factor -= Math.min(0.025, shy * 0.006);
  const label = factor >= 1.035 ? 'starke Hierarchie' : factor <= 0.965 ? 'Kabinenrisiko' : 'stabil';
  return { factor: Math.max(0.90, Math.min(1.08, factor)), label, leaders, divas, mercs, hotheads, shy, frustrated };
}
const hfmV98TeamProfileForMatchBase = teamProfileForMatch;
teamProfileForMatch = function(players, isOwn = false) {
  const profile = hfmV98TeamProfileForMatchBase(players, isOwn);
  const matrix = hfmV98TeamMatrix(profile.roster || players || []);
  profile.chemistry = Math.max(0.88, Math.min(1.12, Number(profile.chemistry || 1) * matrix.factor));
  profile.traitMatrix = matrix;
  if ((profile.roster || []).some(p => hfmV98TraitKey(p) === 'LEADER')) { profile.control += 1; profile.defense += 1; }
  if ((profile.roster || []).some(p => hfmV98TraitKey(p) === 'FIGHTER')) profile.defense += 1;
  if (matrix.divas >= 3 || matrix.frustrated >= 4) profile.control -= 2;
  return profile;
};
function hfmV98DuelTraitFactor(player, skills) {
  const key = hfmV98TraitKey(player);
  const skillText = (skills || []).join('|');
  const isDefense = /zweikampf|stellungsspiel|antizipation|sprungkraft|ausdauer/.test(skillText);
  const isAttack = /abschluss|torriecher|dribbling|technik/.test(skillText);
  const isPass = /passspiel|uebersicht|technik/.test(skillText);
  let factor = Number(hfmV98TraitDef(key).match || 1);
  if (key === 'FIGHTER' && isDefense) factor *= 1.08;
  if (key === 'HOTHEAD' && isDefense) factor *= 1.04;
  if (key === 'SELFISH' && isAttack) factor *= 1.05;
  if (key === 'TEAM_PLAYER' && isPass) factor *= 1.05;
  if (key === 'WEAK_NERVES') factor *= 0.96;
  if (key === 'ICE_COLD' && isAttack) factor *= 1.04;
  if (key === 'ALLROUNDER') factor *= 1.02;
  if (key === 'TRAINING_BEAST') factor *= 0.97;
  return factor;
}
const hfmV98DuelValueBase = duelValue;
duelValue = function(player, skills, randomSpread = 0.45) { return hfmV98DuelValueBase(player, skills, randomSpread) * hfmV98DuelTraitFactor(player, skills); };
const hfmV98PositionFitBase = positionFit;
positionFit = function(player, slotPos) {
  const fit = hfmV98PositionFitBase(player, slotPos);
  if (player && hfmV98TraitKey(player) === 'ALLROUNDER' && fit.factor > 0.2 && fit.factor < 1) return { ...fit, factor: Math.min(0.95, fit.factor + 0.12), label: fit.label === 'Hauptposition' ? fit.label : 'Allrounder-Bonus' };
  return fit;
};
const hfmV98ApplyRatingEventBase = applyRatingEventToRecord;
applyRatingEventToRecord = function(record, player, eventName, intensity = 1, reason = '') {
  let adjusted = intensity;
  const key = hfmV98TraitKey(player);
  if (['yellow','red','foulPenalty'].includes(eventName) && key === 'HOTHEAD') adjusted *= 1.35;
  if (['yellow','red'].includes(eventName) && key === 'FIGHTER') adjusted *= 0.92;
  if (['penaltyMissed','missedBigChance','turnover','badPass'].includes(eventName) && key === 'WEAK_NERVES') adjusted *= 1.25;
  if (['penaltyMissed','missedBigChance'].includes(eventName) && key === 'ICE_COLD') adjusted *= 0.55;
  if (['goal','assist','keyPass','bigChanceCreated'].includes(eventName) && key === 'ETERNAL_TALENT') adjusted *= 1.12;
  if (['winBonus','cleanSheet','passAccuracy'].includes(eventName) && key === 'MODEL_PRO') adjusted *= 1.08;
  hfmV98ApplyRatingEventBase(record, player, eventName, adjusted, reason);
};
const hfmV98GenerateMatchEventsBase = generateMatchEvents;
generateMatchEvents = function(opponent) {
  const plan = hfmV98GenerateMatchEventsBase(opponent);
  const players = plan?.setup?.ownPlayers || [];
  const addEvent = (type, player, minute, text, ratingEvent, intensity = 1) => {
    if (!player) return;
    plan.events.push({ type, minute, team: 'own', playerId: player.id, playerName: player.name, text });
    applyRatingEventToRecord(ensureMatchRatingRecord({ ratingRecords: plan.ratingRecords }, player), player, ratingEvent, intensity, hfmV98TraitLabel(player));
  };
  players.forEach(player => {
    const seed = Math.abs(stableHash(`${player.id}-${state.week}-${opponent}-trait-match-v98`)) % 1000;
    const minute = 10 + (seed % 78);
    const key = hfmV98TraitKey(player);
    if (key === 'HOTHEAD' && seed < 105) addEvent('yellow', player, minute, `${minute}. Min: ${player.name} sieht Gelb nach einem hitzigen Zweikampf.`, 'yellow', 1.1);
    if (key === 'HOTHEAD' && seed >= 105 && seed < 130) addEvent('red', player, minute, `${minute}. Min: Rote Karte fuer ${player.name} nach Frustaktion!`, 'red', 1.1);
    if (key === 'INJURY_PRONE' && seed > 900) addEvent('injury', player, minute, `${minute}. Min: ${player.name} muss nach einem harten Kontakt behandelt werden.`, 'turnover', .4);
    if (key === 'ROBUST' && seed > 930) applyRatingEventToRecord(ensureMatchRatingRecord({ ratingRecords: plan.ratingRecords }, player), player, 'successfulTackle', .5, 'Robust im Zweikampf');
    if (key === 'SUPER_SUB' && Number(player.minutes || 0) < 40) applyRatingEventToRecord(ensureMatchRatingRecord({ ratingRecords: plan.ratingRecords }, player), player, 'keyPass', .35, 'Joker-Mentalitaet');
  });
  plan.events.sort((a,b)=>a.minute-b.minute || String(a.type).localeCompare(String(b.type))).forEach((e,i)=>e.id = `${e.minute}-${e.type}-${i}-${e.playerId||e.scorerId||e.scorerName||''}`);
  return plan;
};
const hfmV98ContractDemandBase = contractDemand;
contractDemand = function(player) {
  const demand = hfmV98ContractDemandBase(player);
  const key = hfmV98TraitKey(player);
  let factor = 1;
  if (key === 'DIVA') factor += 0.22;
  if (key === 'MERCENARY') factor += 0.28;
  if (key === 'AMBITIOUS') factor += 0.10;
  if (key === 'MODEL_PRO') factor -= 0.06;
  if (key === 'LOYAL') factor -= 0.08;
  return { ...demand, salary: Math.round(demand.salary * factor / 1000) * 1000, bonus: Math.round(demand.bonus * Math.max(0.85, factor) / 1000) * 1000 };
};
const hfmV98TransferInterestBase = transferInterest;
transferInterest = function(player, sourceClubName, leagueIndex) {
  let score = hfmV98TransferInterestBase(player, sourceClubName, leagueIndex);
  const key = hfmV98TraitKey(player);
  if (key === 'LOYAL' && Number(player?.minutes || 0) > 50) score -= 16;
  if (key === 'MERCENARY') score += state.money > Number(player?.marketValue || 1) * 1.2 ? 10 : -8;
  if (key === 'DIVA') score += 4;
  return clamp(score, 0, 100);
};
const hfmV98SimulateCurrentMatchBase = simulateCurrentMatch;
simulateCurrentMatch = function() {
  const result = hfmV98SimulateCurrentMatchBase();
  state.players = (state.players || []).map(player => {
    const key = hfmV98TraitKey(player);
    let satisfaction = Number(player.satisfaction || 60);
    const noPlay = Number(player.noPlayWeeks || 0);
    const rating = Number(player.rating || 3);
    if ((key === 'DIVA' || key === 'AMBITIOUS') && noPlay >= 2) satisfaction -= key === 'DIVA' ? 5 : 3;
    if (key === 'MERCENARY' && noPlay >= 3) satisfaction -= 3;
    if (key === 'MODEL_PRO' || key === 'SUPER_SUB') satisfaction += noPlay >= 2 ? 2 : 0;
    if (key === 'WEAK_NERVES' && rating >= 3.8) satisfaction -= 2;
    if (key === 'LOYAL' && Number(player.minutes || 0) > 0) satisfaction += 1;
    return { ...player, satisfaction: clamp(Math.round(satisfaction), 0, 100) };
  });
  return result;
};
