/* Version 104: Fremde Spieleraktionen, verdeckte Skilldetails und guenstigere Scoutingkosten */
function hfmV104EnsureState() {
  if (!state || typeof state !== 'object') return;
  if (!Array.isArray(state.watchlist)) state.watchlist = [];
  if (!state.clubRosterCache || typeof state.clubRosterCache !== 'object') state.clubRosterCache = {};
  if (!state.externalYouthRosterCache || typeof state.externalYouthRosterCache !== 'object') state.externalYouthRosterCache = {};
  if (!Array.isArray(state.youthScoutingReports)) state.youthScoutingReports = [];
}
function hfmV104Js(value) { return JSON.stringify(value == null ? '' : String(value)); }
function hfmV104Num(value, fallback = 0) { const n = Number(value); return Number.isFinite(n) ? n : fallback; }
function hfmV104FindInList(list, playerId) {
  return (Array.isArray(list) ? list : []).find(p => String(p && p.id) === String(playerId)) || null;
}
function hfmV104ResolvePlayer(playerId, clubName, leagueIndex, options = {}) {
  hfmV104EnsureState();
  const id = String(playerId);
  const club = clubName == null ? null : String(clubName);
  const idx = Number(leagueIndex);
  let p = hfmV104FindInList(state.players, id) || hfmV104FindInList(state.academyPlayers, id) || hfmV104FindInList(state.watchlist, id);
  if (!p && club && Number.isFinite(idx)) {
    p = hfmV104FindInList(getClubRoster(club, idx), id);
  }
  if (!p && club && Number.isFinite(idx) && typeof hfmV102GetClubYouthRoster === 'function') {
    p = hfmV104FindInList(hfmV102GetClubYouthRoster(club, idx), id);
    if (p) p = { ...p, youth: true, externalYouth: true };
  }
  if (!p && Array.isArray(state.youthScoutingReports)) {
    for (const report of state.youthScoutingReports) {
      const hit = hfmV104FindInList(report.players, id);
      if (hit) { p = { ...hit, club: report.clubName || club, leagueIndex: Number(report.leagueIndex ?? idx), youth: true, youthScout: true }; break; }
    }
  }
  if (!p && options.player && String(options.player.id) === id) p = options.player;
  if (!p) return null;
  const resolvedClub = club || p.club || ownClubName();
  const resolvedLeague = Number.isFinite(idx) ? idx : Number(p.leagueIndex ?? OWN_LEAGUE_INDEX);
  return { ...p, club: resolvedClub, leagueIndex: resolvedLeague };
}
function hfmV104IsKnown(player) {
  if (!player) return false;
  if (typeof hfmV87IsOwnPlayer === 'function' && hfmV87IsOwnPlayer(player)) return true;
  if (player.youth || player.externalYouth || player.youthScout) {
    if (typeof hfmV102ClubYouthKnown === 'function' && hfmV102ClubYouthKnown(player.club, player.leagueIndex)) return true;
  }
  return typeof isPlayerKnown === 'function' ? isPlayerKnown(player) : false;
}
const hfmV104OpenPlayerProfileBase = openPlayerProfile;
openPlayerProfile = function(playerId, clubName, leagueIndex = OWN_LEAGUE_INDEX) {
  const p = hfmV104ResolvePlayer(playerId, clubName, leagueIndex);
  if (!p) {
    if (typeof hfmV104OpenPlayerProfileBase === 'function') return hfmV104OpenPlayerProfileBase(playerId, clubName, leagueIndex);
    return false;
  }
  state.playerProfile = p;
  render();
  return false;
};
window.openPlayerProfile = openPlayerProfile;
const hfmV104AddToWatchlistBase = addToWatchlist;
addToWatchlist = function(playerId, clubName, leagueIndex = OWN_LEAGUE_INDEX) {
  const p = hfmV104ResolvePlayer(playerId, clubName, leagueIndex);
  if (!p) {
    if (typeof hfmV104AddToWatchlistBase === 'function') return hfmV104AddToWatchlistBase(playerId, clubName, leagueIndex);
    return false;
  }
  if (watchlistHas(p.id)) { alert(`${p.name} ist bereits auf der Beobachtungsliste.`); return false; }
  state.watchlist.push({ ...p, club: p.club || clubName, leagueIndex: Number(p.leagueIndex ?? leagueIndex) });
  alert(`${p.name} wurde auf die Beobachtungsliste gesetzt.`);
  render();
  return false;
};
window.addToWatchlist = addToWatchlist;
const hfmV104MakeContractOfferBase = makeContractOffer;
makeContractOffer = function(playerId, clubName, leagueIndex = OWN_LEAGUE_INDEX) {
  const p = hfmV104ResolvePlayer(playerId, clubName, leagueIndex);
  if (!p) {
    if (typeof hfmV104MakeContractOfferBase === 'function') return hfmV104MakeContractOfferBase(playerId, clubName, leagueIndex);
    return false;
  }
  if (p.youth || p.externalYouth || p.youthScout) {
    if (Number(p.age) < 16) { alert('Jugendspieler koennen erst ab 16 Jahren ein Vertragsangebot erhalten.'); return false; }
    if (typeof hfmV103OpenExternalYouthNegotiation === 'function') return hfmV103OpenExternalYouthNegotiation(p.id, p.club, p.leagueIndex);
    if (typeof hfmV101OpenYouthNegotiation === 'function') { hfmV101OpenYouthNegotiation(String(p.id)); return false; }
  }
  if (!hfmV104IsKnown(p)) { alert('Diesen Spieler musst du zuerst scouten, bevor du ein seriöses Vertragsangebot machen kannst.'); return false; }
  return hfmV104MakeContractOfferBase(p.id, p.club, p.leagueIndex);
};
