/* Version 106: robuste Klick-Handler fuer Fremdspieler-Buttons und Wohlfühlfaktor-Details */
function hfmV106Data(value) {
  try { return encodeURIComponent(JSON.stringify(value == null ? '' : String(value))); }
  catch (err) { return ''; }
}
function hfmV106ReadData(value) {
  try { return JSON.parse(decodeURIComponent(value || '%22%22')); }
  catch (err) { return value || ''; }
}
function hfmV106PlayerActionAttrs(action, p) {
  return `data-fm-action="${action}" data-player-id="${hfmV106Data(p && p.id)}" data-club="${hfmV106Data(p && p.club)}" data-league-index="${Number((p && p.leagueIndex) ?? OWN_LEAGUE_INDEX)}"`;
}
function hfmV106StartYouthScouting(clubName, leagueIndex) {
  if (typeof hfmV103StartYouthScoutClub === 'function') return hfmV103StartYouthScoutClub(clubName, Number(leagueIndex));
  if (typeof hfmV101StartYouthScouting === 'function') return hfmV101StartYouthScouting(clubName, Number(leagueIndex));
  alert('Jugendscouting ist aktuell nicht verfügbar.');
  return false;
}
function hfmV106HandlePlayerAction(action, playerId, clubName, leagueIndex) {
  const idx = Number(leagueIndex ?? OWN_LEAGUE_INDEX);
  if (action === 'open') return openPlayerProfile(playerId, clubName, idx);
  if (action === 'watch') return addToWatchlist(playerId, clubName, idx);
  if (action === 'scout') return scoutPlayer(playerId, clubName, idx);
  if (action === 'offer') return makeContractOffer(playerId, clubName, idx);
  if (action === 'youthScout') return hfmV106StartYouthScouting(clubName, idx);
  return false;
}
const hfmV106ExternalActionButtonsBase = hfmV104ExternalActionButtons;
hfmV104ExternalActionButtons = function(p, known) {
  const job = typeof scoutingJobStatusText === 'function' ? scoutingJobStatusText('player', { playerId: p.id }) : '';
  const watch = watchlistHas(p.id)
    ? '<button type="button" class="ghost" disabled>Auf Beobachtungsliste</button>'
    : `<button type="button" class="ghost" ${hfmV106PlayerActionAttrs('watch', p)}>Zur Beobachtungsliste hinzufügen</button>`;
  if (p.youth || p.externalYouth || p.youthScout) {
    const youthJob = typeof hfmV101YouthJobStatus === 'function' ? hfmV101YouthJobStatus(p.club, p.leagueIndex) : null;
    const report = typeof hfmV102GetYouthReport === 'function' ? hfmV102GetYouthReport(p.club, p.leagueIndex) : null;
    const slotsFull = typeof hfmV99ScoutingHasFreeSlot === 'function' && !hfmV99ScoutingHasFreeSlot();
    const scoutText = report ? 'Jugend gescoutet' : youthJob ? `Jugendscouting läuft · noch ${Math.max(1, Math.ceil(youthJob.remainingDays))} Tage` : slotsFull ? 'Scoutingsystem ausgelastet' : 'Jugend scouten';
    const scout = known ? '' : `<button type="button" class="primary" ${youthJob || report || slotsFull ? 'disabled' : ''} ${hfmV106PlayerActionAttrs('youthScout', p)}>${scoutText}</button>`;
    const offer = known ? (Number(p.age) >= 16 ? `<button type="button" class="primary" ${hfmV106PlayerActionAttrs('offer', p)}>Vertragsangebot / Versprechen</button>` : '<button type="button" class="primary" disabled>Noch zu jung für Vertrag</button>') : '';
    return `<div class="playerActions">${watch}${scout}${offer}</div>`;
  }
  const scout = known ? '' : `<button type="button" class="primary" ${job ? 'disabled' : ''} ${hfmV106PlayerActionAttrs('scout', p)}>${job || `Spieler scouten · ${euro(scoutPlayerCost(p))}`}</button>`;
  const offer = known ? `<button type="button" class="primary" ${hfmV106PlayerActionAttrs('offer', p)}>Vertragsangebot</button>` : '';
  return `<div class="playerActions">${watch}${scout}${offer}</div>`;
};
window.hfmV104ExternalActionButtons = hfmV104ExternalActionButtons;
hfmV104PlayerCard = function(p, known) {
  const attrs = hfmV106PlayerActionAttrs('open', p);
  const meta = known ? knownPlayerMeta(p) : hfmV104UnknownPlayerMeta(p);
  return `<div class="player"><div class="playerTop"><button type="button" class="linkButton playerNameLink" ${attrs}>${p.name}</button><span>${positionText(p)} · ${p.age} Jahre</span></div><div class="meta">${meta}</div>${hfmV104ExternalActionButtons(p, known)}</div>`;
};
window.hfmV104PlayerCard = hfmV104PlayerCard;
function hfmV106OpenComfortDetails(playerId, clubName, leagueIndex) {
  const p = hfmV104ResolvePlayer(playerId, clubName, Number(leagueIndex ?? OWN_LEAGUE_INDEX)) || (state.playerProfile && String(state.playerProfile.id) === String(playerId) ? state.playerProfile : null);
  state.comfortDetailsPlayerId = String(playerId || (p && p.id) || '');
  state.comfortDetailsContext = p ? { playerId: String(p.id), clubName: p.club || clubName || '', leagueIndex: Number(p.leagueIndex ?? leagueIndex ?? OWN_LEAGUE_INDEX) } : { playerId: String(playerId || ''), clubName: clubName || '', leagueIndex: Number(leagueIndex ?? OWN_LEAGUE_INDEX) };
  render();
  return false;
}
window.hfmV106OpenComfortDetails = hfmV106OpenComfortDetails;
hfmV105OpenComfortDetails = function(playerId, clubName, leagueIndex) { return hfmV106OpenComfortDetails(playerId, clubName, leagueIndex); };
window.hfmV105OpenComfortDetails = hfmV105OpenComfortDetails;
hfmV105ComfortBar = function(player, compact = false) {
  const score = hfmV105PlayerComfort(player);
  const label = hfmV105ComfortLabel(score);
  const p = player || {};
  return `<button type="button" class="comfortScale ${compact ? 'compactComfortScale' : ''}" data-comfort-open="1" ${hfmV106PlayerActionAttrs('comfort', p)} title="Details zum Wohlfühlfaktor anzeigen"><span><b>Wohlfühlfaktor</b> ${score}/100</span><i><em style="width:${score}%"></em></i><small>${label}</small></button>`;
};
window.hfmV105ComfortBar = hfmV105ComfortBar;
hfmV105ComfortCard = function(p, known) {
  if (!known) return `<article class="card"><p>Wohlfühlfaktor</p><h2>?</h2><span>Scouting erforderlich</span></article>`;
  const c = hfmV105PlayerComfort(p);
  return `<button type="button" class="card comfortCard comfortCardButton" data-comfort-open="1" ${hfmV106PlayerActionAttrs('comfort', p)}><p>Wohlfühlfaktor</p><h2>${c}/100</h2><span>${hfmV105ComfortLabel(c)}</span></button>`;
};
window.hfmV105ComfortCard = hfmV105ComfortCard;
const hfmV106ComfortDetailsModalBase = hfmV105ComfortDetailsModal;
hfmV105ComfortDetailsModal = function() {
  const ctx = state.comfortDetailsContext || null;
  if (ctx && ctx.playerId) {
    const p = hfmV104ResolvePlayer(ctx.playerId, ctx.clubName, ctx.leagueIndex) || (state.playerProfile && String(state.playerProfile.id) === String(ctx.playerId) ? state.playerProfile : null);
    if (p) state.comfortDetailsPlayerId = String(p.id);
  }
  const html = hfmV106ComfortDetailsModalBase();
  return html ? html.replace('class="lineupModalBackdrop"', 'class="lineupModalBackdrop comfortDetailsModal"') : '';
};
window.hfmV105ComfortDetailsModal = hfmV105ComfortDetailsModal;
function hfmV106AttachDelegatedHandlers() {
  if (window.hfmV106DelegatedHandlersAttached) return;
  window.hfmV106DelegatedHandlersAttached = true;
  document.addEventListener('click', function(event) {
    const comfort = event.target.closest && event.target.closest('[data-comfort-open]');
    if (comfort) {
      event.preventDefault();
      event.stopPropagation();
      return hfmV106OpenComfortDetails(hfmV106ReadData(comfort.dataset.playerId), hfmV106ReadData(comfort.dataset.club), Number(comfort.dataset.leagueIndex || OWN_LEAGUE_INDEX));
    }
    const btn = event.target.closest && event.target.closest('[data-fm-action]');
    if (!btn || btn.dataset.fmAction === 'comfort') return;
    event.preventDefault();
    event.stopPropagation();
    return hfmV106HandlePlayerAction(btn.dataset.fmAction, hfmV106ReadData(btn.dataset.playerId), hfmV106ReadData(btn.dataset.club), Number(btn.dataset.leagueIndex || OWN_LEAGUE_INDEX));
  }, true);
}
const hfmV106RenderBase = render;
render = function() {
  const result = hfmV106RenderBase();
  hfmV106AttachDelegatedHandlers();
  const app = document.getElementById('app');
  if (app && state.comfortDetailsPlayerId && !app.querySelector('.comfortDetailsModal')) {
    const modal = hfmV105ComfortDetailsModal();
    if (modal) app.insertAdjacentHTML('beforeend', modal);
  }
  return result;
};
window.render = render;
try { hfmV106AttachDelegatedHandlers(); render(); } catch (err) { console.error(err); }

/* Version 107: Transfer-/Vertragsverhandlung fuer fremde Spieler statt Sofortverpflichtung */
function hfmV107EnsureTransferNegotiationState() {
  if (!state || typeof state !== 'object') return;
  if (!state.transferNegotiation || typeof state.transferNegotiation !== 'object') state.transferNegotiation = null;
  if (!state.transferNegotiationOffer || typeof state.transferNegotiationOffer !== 'object') {
    state.transferNegotiationOffer = { years: 3, salary: 25000, bonus: 50000, fee: 0, role: 'Rotation' };
  }
}
function hfmV107ResolveTransferPlayer(playerId, clubName, leagueIndex) {
  const idx = Number(leagueIndex ?? OWN_LEAGUE_INDEX);
  let p = null;
  if (String(clubName || '') === 'Ablösefrei') {
    p = (state.transferFreeAgents || []).find(x => String(x.id) === String(playerId)) || null;
    if (p) return { ...p, club: 'Ablösefrei', leagueIndex: OWN_LEAGUE_INDEX, freeAgent: true };
  }
  if (typeof hfmV104ResolvePlayer === 'function') p = hfmV104ResolvePlayer(playerId, clubName, idx);
  if (!p && typeof getClubRoster === 'function') p = (getClubRoster(clubName, idx) || []).find(x => String(x.id) === String(playerId)) || null;
  if (!p) return null;
  return { ...p, club: clubName || p.club, leagueIndex: Number(p.leagueIndex ?? idx) };
}
function hfmV107TransferBaseFee(player, options = {}) {
  if (!player || player.freeAgent || String(player.club || '') === 'Ablösefrei') return 0;
  if (options.transferList && typeof transferListPrice === 'function') return Number(transferListPrice(player) || 0);
  const interest = typeof transferInterest === 'function' ? Number(transferInterest(player, player.club, player.leagueIndex) || 50) : 50;
  const premium = interest < 45 ? 1.28 : interest < 60 ? 1.16 : interest < 75 ? 1.08 : 1.0;
  return Math.max(25000, Math.round(Number(player.marketValue || 150000) * premium / 10000) * 10000);
}
function hfmV107TransferDemand(player, options = {}) {
  const comfort = typeof hfmV105PlayerComfort === 'function' ? hfmV105PlayerComfort(player) : Number(player && player.satisfaction || 60);
  const interest = typeof transferInterest === 'function' ? Number(transferInterest(player, player.club, player.leagueIndex) || 50) : 50;
  const baseSalary = Number(player && player.salary || Math.round(((Number(player && player.strength || 55) * 850) + (Number(player && player.talent || 2) * 2500)) / 1000) * 1000);
  let salaryFactor = 1.12;
  if (interest < 45) salaryFactor += 0.30;
  else if (interest < 60) salaryFactor += 0.16;
  if (comfort >= 78 && !player.freeAgent) salaryFactor += 0.10;
  if (comfort <= 42) salaryFactor -= 0.10;
  if (player && player.trait === 'mercenary') salaryFactor += 0.14;
  if (player && player.trait === 'diva') salaryFactor += 0.12;
  const salary = Math.max(8000, Math.round(baseSalary * salaryFactor / 1000) * 1000);
  const bonus = Math.max(10000, Math.round(salary * (player && player.freeAgent ? 3.0 : 2.0) / 5000) * 5000);
  const years = Math.max(1, Math.min(5, Number(player && player.age || 24) >= 31 ? 2 : Number(player && player.age || 24) <= 22 ? 4 : 3));
  const fee = hfmV107TransferBaseFee(player, options);
  return { salary, bonus, years, fee, interest, comfort };
}
function hfmV107RoleScore(role) {
  if (role === 'Stammspieler') return 14;
  if (role === 'Wichtiger Spieler') return 9;
  if (role === 'Rotation') return 4;
  if (role === 'Talent aufbauen') return 6;
  return 0;
}
function hfmV107OpenTransferNegotiation(playerId, clubName, leagueIndex = OWN_LEAGUE_INDEX, options = {}) {
  hfmV107EnsureTransferNegotiationState();
  const player = hfmV107ResolveTransferPlayer(playerId, clubName, leagueIndex);
  if (!player) { alert('Spieler konnte nicht gefunden werden.'); return false; }
  if (player.youth || player.externalYouth || player.youthScout) {
    if (Number(player.age) < 16) { alert('Jugendspieler koennen erst ab 16 Jahren ein Vertragsangebot erhalten.'); return false; }
    if (typeof hfmV103OpenExternalYouthNegotiation === 'function') return hfmV103OpenExternalYouthNegotiation(player.id, player.club, player.leagueIndex);
    if (typeof hfmV101OpenYouthNegotiation === 'function') { hfmV101OpenYouthNegotiation(String(player.id)); return false; }
  }
  if (!player.freeAgent && typeof hfmV104IsKnown === 'function' && !hfmV104IsKnown(player)) {
    alert('Diesen Spieler musst du zuerst scouten, bevor du ein seriöses Vertragsangebot machen kannst.');
    return false;
  }
  const demand = hfmV107TransferDemand(player, options);
  if (demand.interest < 25) {
    alert(`${player.name} hat aktuell praktisch kein Interesse an deinem Verein. Eine Verhandlung ist derzeit nicht sinnvoll.`);
    return false;
  }
  state.transferNegotiation = {
    playerId: String(player.id),
    clubName: player.club || clubName || '',
    leagueIndex: Number(player.leagueIndex ?? leagueIndex ?? OWN_LEAGUE_INDEX),
    round: 1,
    maxRounds: demand.interest < 45 ? 2 : 3,
    transferList: !!options.transferList,
    freeAgent: !!player.freeAgent,
    lastMessage: 'Der Berater ist bereit zu verhandeln. Ein Klick verpflichtet den Spieler nicht mehr direkt - du musst ein Angebot abgeben.'
  };
  state.transferNegotiationOffer = {
    years: demand.years,
    salary: demand.salary,
    bonus: demand.bonus,
    fee: demand.fee,
    role: demand.interest < 50 ? 'Stammspieler' : 'Rotation'
  };
  render();
  return false;
}
function hfmV107CloseTransferNegotiation() {
  state.transferNegotiation = null;
  render();
  return false;
}
function hfmV107SetTransferOfferField(field, value) {
  hfmV107EnsureTransferNegotiationState();
  if (!state.transferNegotiationOffer) state.transferNegotiationOffer = {};
  if (field === 'role') state.transferNegotiationOffer.role = String(value || 'Rotation');
  else {
    const n = Number(value || 0);
    if (field === 'years') state.transferNegotiationOffer.years = Math.max(1, Math.min(5, Math.round(n)));
    if (field === 'salary') state.transferNegotiationOffer.salary = Math.max(0, Math.round(n));
    if (field === 'bonus') state.transferNegotiationOffer.bonus = Math.max(0, Math.round(n));
    if (field === 'fee') state.transferNegotiationOffer.fee = Math.max(0, Math.round(n));
  }
  render();
  return false;
}
function hfmV107CommitTransfer(player, offer, neg) {
  const fee = Number(offer.fee || 0);
  const bonus = Number(offer.bonus || 0);
  const total = fee + bonus;
  if (state.money < total) { alert(`Nicht genug Geld. Benötigt werden ${euro(total)}.`); return false; }
  state.money -= total;
  state.finance.expenseTransfers = Number(state.finance.expenseTransfers || 0) + fee;
  state.finance.expenseSalaries = Number(state.finance.expenseSalaries || 0) + bonus;
  if (typeof hfmV65RemoveFromSourceRoster === 'function') hfmV65RemoveFromSourceRoster(player);
  else if (player.freeAgent) state.transferFreeAgents = (state.transferFreeAgents || []).filter(p => String(p.id) !== String(player.id));
  const nextId = Math.max(0, ...((state.players || []).map(p => Number(p.id) || 0))) + 1;
  const incoming = ensurePlayerSkillProfile({
    ...player,
    id: nextId,
    club: ownClubName(),
    leagueIndex: OWN_LEAGUE_INDEX,
    youth: false,
    externalYouth: false,
    youthScout: false,
    loan: null,
    contractYears: Math.max(1, Math.min(5, Number(offer.years || 3))),
    salary: Number(offer.salary || player.salary || 20000),
    progress: Number(player.progress || 0),
    rating: Number(player.rating || 3.0),
    minutes: 0,
    satisfaction: Math.max(55, Number(player.satisfaction || 60))
  });
  if (typeof hfmV98EnsureCharacterTrait === 'function') hfmV98EnsureCharacterTrait(incoming);
  if (typeof hfmV105EnsureComfortPlayer === 'function') hfmV105EnsureComfortPlayer(incoming);
  state.players.push(incoming);
  state.watchlist = (state.watchlist || []).filter(p => String(p.id) !== String(player.id));
  state.transferFreeAgents = (state.transferFreeAgents || []).filter(p => String(p.id) !== String(player.id));
  state.transferNegotiation = null;
  if (typeof initLineup === 'function') initLineup();
  alert(`${player.name} nimmt dein Angebot an und unterschreibt fuer ${incoming.contractYears} Jahre. Kosten: ${euro(total)}.`);
  render();
  return true;
}
function hfmV107SubmitTransferOffer() {
  hfmV107EnsureTransferNegotiationState();
  const neg = state.transferNegotiation;
  if (!neg) return false;
  const player = hfmV107ResolveTransferPlayer(neg.playerId, neg.clubName, neg.leagueIndex);
  if (!player) { state.transferNegotiation = null; render(); return false; }
  const demand = hfmV107TransferDemand(player, { transferList: neg.transferList });
  const offer = state.transferNegotiationOffer || {};
  const salaryScore = Number(offer.salary || 0) / Math.max(1, demand.salary) * 42;
  const bonusScore = Number(offer.bonus || 0) / Math.max(1, demand.bonus) * 18;
  const yearsScore = Number(offer.years || 1) / Math.max(1, demand.years) * 12;
  const feeScore = player.freeAgent ? 10 : Number(offer.fee || 0) / Math.max(1, demand.fee) * 14;
  const interestScore = (demand.interest - 45) / 2.3;
  const comfortScore = player.freeAgent ? 0 : (50 - demand.comfort) / 5;
  const score = salaryScore + bonusScore + yearsScore + feeScore + hfmV107RoleScore(offer.role) + interestScore + comfortScore;
  const required = neg.transferList ? 78 : (demand.interest < 45 ? 94 : 84);
  if (score >= required) return hfmV107CommitTransfer(player, offer, neg);
  if (neg.round >= neg.maxRounds || score < required - 28) {
    const name = player.name;
    state.transferNegotiation = null;
    alert(`${name} lehnt ab. Der Berater findet dein Angebot nicht ueberzeugend genug.`);
    render();
    return false;
  }
  neg.round += 1;
  const wantsRole = demand.interest < 55 && offer.role !== 'Stammspieler';
  state.transferNegotiationOffer.salary = Math.round(Math.max(Number(offer.salary || 0) * 1.1, demand.salary) / 1000) * 1000;
  state.transferNegotiationOffer.bonus = Math.round(Math.max(Number(offer.bonus || 0) * 1.15, demand.bonus) / 5000) * 5000;
  if (!player.freeAgent) state.transferNegotiationOffer.fee = Math.round(Math.max(Number(offer.fee || 0) * 1.07, demand.fee) / 10000) * 10000;
  if (wantsRole) state.transferNegotiationOffer.role = 'Stammspieler';
  neg.lastMessage = wantsRole
    ? 'Gegenforderung: Der Spieler will eine wichtigere sportliche Rolle und bessere Konditionen.'
    : 'Gegenforderung: Der Berater verlangt bessere Konditionen, sonst platzt die Verhandlung.';
  render();
  return false;
}
function hfmV107TransferNegotiationModal() {
  hfmV107EnsureTransferNegotiationState();
  const neg = state.transferNegotiation;
  if (!neg) return '';
  const player = hfmV107ResolveTransferPlayer(neg.playerId, neg.clubName, neg.leagueIndex);
  if (!player) return '';
  const demand = hfmV107TransferDemand(player, { transferList: neg.transferList });
  const offer = state.transferNegotiationOffer || {};
  const total = Number(offer.fee || 0) + Number(offer.bonus || 0);
  const roles = ['Talent aufbauen','Rotation','Wichtiger Spieler','Stammspieler'];
  const feeField = player.freeAgent
    ? `<article class="card"><p>Ablöse</p><h2>0 €</h2><span>ablösefrei / nur Handgeld</span></article>`
    : `<label class="fieldLabel">Ablöseangebot an ${player.club}</label><input type="number" value="${Number(offer.fee || 0)}" step="10000" onchange="hfmV107SetTransferOfferField('fee', this.value)" />`;
  return `<div class="lineupModalBackdrop lineupModalTop" role="dialog" aria-modal="true"><div class="lineupModal"><div class="modalHeader"><div><p class="eyebrow">Transferverhandlung · Runde ${neg.round}/${neg.maxRounds}</p><h2>${player.name}</h2></div><button type="button" class="ghost closeButton" onclick="hfmV107CloseTransferNegotiation()">Schließen</button></div><div class="grid compact"><article class="card"><p>Budget</p><h2>${euro(state.money)}</h2><span>aktueller Kontostand</span></article><article class="card"><p>Gesamtkosten sofort</p><h2>${euro(total)}</h2><span>Ablöse + Bonus/Handgeld</span></article><article class="card"><p>Wechselbereitschaft</p><h2>${demand.interest}%</h2><span>${typeof transferInterestText === 'function' ? transferInterestText(player, player.club, player.leagueIndex) : 'Einschätzung'}</span></article></div><div class="infoBox"><b>${neg.lastMessage || 'Der Berater wartet auf dein Angebot.'}</b><br>Orientierung des Beraters: ${demand.years} Jahre, Gehalt ca. ${euro(demand.salary)}, Bonus ca. ${euro(demand.bonus)}${player.freeAgent ? '' : `, Ablöse ca. ${euro(demand.fee)}`}. Wohlfühlfaktor beim aktuellen Verein: ${demand.comfort}/100.</div>${feeField}<label class="fieldLabel">Vertragsdauer</label><select onchange="hfmV107SetTransferOfferField('years', this.value)">${[1,2,3,4,5].map(y => `<option value="${y}" ${Number(offer.years)==y?'selected':''}>${y} Jahre</option>`).join('')}</select><label class="fieldLabel">Gehalt pro Monat</label><input type="number" value="${Number(offer.salary || 0)}" step="1000" onchange="hfmV107SetTransferOfferField('salary', this.value)" /><label class="fieldLabel">Bonus / Handgeld</label><input type="number" value="${Number(offer.bonus || 0)}" step="5000" onchange="hfmV107SetTransferOfferField('bonus', this.value)" /><label class="fieldLabel">Sportliches Versprechen / Rolle</label><select onchange="hfmV107SetTransferOfferField('role', this.value)">${roles.map(r => `<option value="${r}" ${String(offer.role||'')===r?'selected':''}>${r}</option>`).join('')}</select><div class="modalActions"><button type="button" class="ghost full" onclick="hfmV107CloseTransferNegotiation()">Abbrechen</button><button type="button" class="primary full" onclick="hfmV107SubmitTransferOffer()">Angebot abgeben</button></div></div></div>`;
}
const hfmV107MakeContractOfferBase = makeContractOffer;
makeContractOffer = function(playerId, clubName, leagueIndex = OWN_LEAGUE_INDEX) {
  const p = hfmV107ResolveTransferPlayer(playerId, clubName, leagueIndex);
  if (p && (p.youth || p.externalYouth || p.youthScout)) {
    if (Number(p.age) < 16) { alert('Jugendspieler koennen erst ab 16 Jahren ein Vertragsangebot erhalten.'); return false; }
    if (typeof hfmV103OpenExternalYouthNegotiation === 'function') return hfmV103OpenExternalYouthNegotiation(p.id, p.club, p.leagueIndex);
    if (typeof hfmV101OpenYouthNegotiation === 'function') { hfmV101OpenYouthNegotiation(String(p.id)); return false; }
  }
  return hfmV107OpenTransferNegotiation(playerId, clubName, leagueIndex, { transferList: false });
};
window.makeContractOffer = makeContractOffer;
const hfmV107BuyTransferListedPlayerBase = buyTransferListedPlayer;
buyTransferListedPlayer = function(playerId, clubName, leagueIndex = OWN_LEAGUE_INDEX) {
  return hfmV107OpenTransferNegotiation(playerId, clubName, leagueIndex, { transferList: true });
};
window.buyTransferListedPlayer = buyTransferListedPlayer;
const hfmV107RenderBase = render;
render = function() {
  const result = hfmV107RenderBase();
  const app = document.getElementById('app');
  if (app && state.transferNegotiation && !app.querySelector('.transferNegotiationModalV107')) {
    const modal = hfmV107TransferNegotiationModal().replace('lineupModalBackdrop', 'lineupModalBackdrop transferNegotiationModalV107');
    if (modal) app.insertAdjacentHTML('beforeend', modal);
  }
  return result;
};
window.render = render;
try { hfmV107EnsureTransferNegotiationState(); render(); } catch (err) { console.error(err); }

/* === v108: zweistufiges Transfersystem, KI-Markt, Transferberichte === */
function hfmV108EnsureTransferState() {
  if (!state || typeof state !== 'object') return;
  if (!Array.isArray(state.transferOutOfferLocks)) state.transferOutOfferLocks = [];
  if (!Array.isArray(state.transferBiweeklyReports)) state.transferBiweeklyReports = [];
  if (!state.transferNegotiationOffer || typeof state.transferNegotiationOffer !== 'object') {
    state.transferNegotiationOffer = { fee: 0, years: 3, salary: 25000, bonus: 50000, role: 'Rotation', appearanceBonus: 0, goalBonus: 0, releaseClause: 0 };
  }
}
function hfmV108RoundMoney(value, step = 10000) {
  return Math.max(0, Math.round(Number(value || 0) / step) * step);
}
function hfmV108MarketValue(player, clubName = '', leagueIndex = OWN_LEAGUE_INDEX) {
  const p = player || {};
  const strength = Number(p.strength || 50);
  const age = Number(p.age || 24);
  const talent = Number(p.talent || 2);
  let base = Math.pow(strength, 2.35) * 320;
  let ageFactor = 1.0;
  if (age <= 22) ageFactor = 1.2;
  else if (age <= 28) ageFactor = 1.0;
  else if (age <= 32) ageFactor = 0.7;
  else ageFactor = 0.4;
  const potentialFactor = 1 + Math.max(0, talent - 3) * 0.18 + (age <= 21 ? talent * 0.04 : 0);
  const years = Number(p.contractYears || 2);
  let contractFactor = years >= 3 ? 1.0 : years >= 2 ? 0.85 : years >= 1 ? 0.55 : 0.0;
  const league = LEAGUES[Number(leagueIndex)] || {};
  const prestigeFactor = league.tier === 'Topliga' ? 1.28 : league.tier === 'Stark' ? 1.12 : league.tier === 'Spezialliga' ? 1.04 : 0.94;
  const value = base * ageFactor * potentialFactor * contractFactor * prestigeFactor;
  return hfmV108RoundMoney(Math.max(25000, value), value > 1000000 ? 50000 : 10000);
}
function hfmV108PlayerStatusAtClub(player, clubName, leagueIndex) {
  const p = player || {};
  const roster = getClubRoster(clubName, Number(leagueIndex)).filter(x => !x.youth && !x.externalYouth);
  const samePos = roster.filter(x => x.pos === p.pos).sort((a,b) => Number(b.strength || 0) - Number(a.strength || 0));
  const rank = samePos.findIndex(x => String(x.id) === String(p.id)) + 1;
  const rosterAvg = roster.length ? roster.reduce((s,x) => s + Number(x.strength || 0), 0) / roster.length : Number(p.strength || 0);
  const comfort = typeof hfmV105PlayerComfort === 'function' ? hfmV105PlayerComfort(p) : Number(p.satisfaction || 60);
  if (p.aiListed || p.transferListedByAi || (typeof isTransferListed === 'function' && isTransferListed(p))) return 'transferliste';
  if (comfort <= 38 || Number(p.contractYears || 2) <= 1 || rank >= 3) return 'ergaenzung';
  if (Number(p.strength || 0) >= rosterAvg + 6 && rank <= 1) return 'schluessel';
  return 'rotation';
}
function hfmV108SellerDemand(player, clubName, leagueIndex) {
  const market = hfmV108MarketValue(player, clubName, leagueIndex);
  const status = player.freeAgent || String(clubName) === 'Ablösefrei' ? 'free' : hfmV108PlayerStatusAtClub(player, clubName, leagueIndex);
  const seed = stableHash(`${player.id}-${clubName}-${leagueIndex}-${seasonLabel()}`);
  let askFactor = 1.08, minFactor = 0.98, label = 'normaler Rotationsspieler';
  if (status === 'schluessel') { askFactor = 1.55 + (seed % 40) / 100; minFactor = 1.35; label = 'Schlüsselspieler'; }
  else if (status === 'rotation') { askFactor = 1.03 + (seed % 18) / 100; minFactor = 0.92; label = 'Rotationsspieler'; }
  else if (status === 'ergaenzung') { askFactor = 0.78 + (seed % 16) / 100; minFactor = 0.68; label = 'Ergänzungsspieler / unzufrieden'; }
  else if (status === 'transferliste') { askFactor = 0.56 + (seed % 15) / 100; minFactor = 0.50; label = 'auf der Transferliste'; }
  const sellerRep = typeof hfmV65ClubReputation === 'function' ? hfmV65ClubReputation(clubName, Number(leagueIndex)) : 55;
  const buyerRep = ownCombinedImage ? ownCombinedImage() : 50;
  if (sellerRep > buyerRep + 20 && status !== 'transferliste') askFactor += 0.12;
  return { market, status, label, ask: hfmV108RoundMoney(market * askFactor, 10000), min: hfmV108RoundMoney(market * minFactor, 10000) };
}
function hfmV108TransferInterest(player, clubName, leagueIndex) {
  const interest = typeof transferInterest === 'function' ? Number(transferInterest(player, clubName, Number(leagueIndex)) || 50) : 50;
  const comfort = typeof hfmV105PlayerComfort === 'function' ? hfmV105PlayerComfort(player) : Number(player.satisfaction || 60);
  const currentRep = typeof hfmV65ClubReputation === 'function' ? hfmV65ClubReputation(clubName, Number(leagueIndex)) : 50;
  const ownRep = typeof ownCombinedImage === 'function' ? ownCombinedImage() : 50;
  let score = interest + Math.max(-16, Math.min(12, ownRep - currentRep)) + (50 - comfort) * 0.22;
  if (player.trait === 'mercenary') score += 7;
  if (player.trait === 'vereinstreu') score -= 8;
  if (Number(player.contractYears || 2) <= 1) score += 8;
  return Math.round(clamp(score, 0, 100));
}
function hfmV108ContractDemand(player, clubName, leagueIndex) {
  const baseSalary = Number(player.salary || Math.round((Number(player.strength || 55) * 950 + Number(player.talent || 2) * 2500) / 1000) * 1000);
  const currentRep = typeof hfmV65ClubReputation === 'function' ? hfmV65ClubReputation(clubName, Number(leagueIndex)) : 50;
  const ownRep = typeof ownCombinedImage === 'function' ? ownCombinedImage() : 50;
  const interest = hfmV108TransferInterest(player, clubName, leagueIndex);
  let factor = 1.18;
  if (ownRep < currentRep) factor += Math.min(0.55, (currentRep - ownRep) / 100);
  if (interest < 50) factor += 0.22;
  if (player.trait === 'mercenary') factor += 0.14;
  if (player.trait === 'diva') factor += 0.12;
  if ((typeof hfmV105PlayerComfort === 'function' ? hfmV105PlayerComfort(player) : 60) < 40) factor -= 0.08;
  const salary = Math.max(7000, hfmV108RoundMoney(baseSalary * factor, 1000));
  const bonus = hfmV108RoundMoney(salary * (interest < 50 ? 3.2 : 2.1), 5000);
  const age = Number(player.age || 24);
  const years = age <= 22 ? 3 : age >= 31 ? 2 : 3;
  return { salary, bonus, years, role: Number(player.strength || 0) >= 70 ? 'Wichtiger Spieler' : 'Rotation', interest };
}
function hfmV108OpenTransferNegotiation(playerId, clubName, leagueIndex = OWN_LEAGUE_INDEX, options = {}) {
  hfmV108EnsureTransferState();
  const player = hfmV107ResolveTransferPlayer(playerId, clubName, leagueIndex);
  if (!player) { alert('Spieler konnte nicht gefunden werden.'); return false; }
  if (player.youth || player.externalYouth || player.youthScout) {
    if (Number(player.age) < 16) { alert('Jugendspieler können erst ab 16 Jahren ein Vertragsangebot erhalten.'); return false; }
    if (typeof hfmV103OpenExternalYouthNegotiation === 'function') return hfmV103OpenExternalYouthNegotiation(player.id, player.club, player.leagueIndex);
    if (typeof hfmV101OpenYouthNegotiation === 'function') { hfmV101OpenYouthNegotiation(String(player.id)); return false; }
  }
  if (!player.freeAgent && typeof hfmV104IsKnown === 'function' && !hfmV104IsKnown(player)) {
    alert('Diesen Spieler musst du zuerst scouten, bevor du ein seriöses Vertragsangebot machen kannst.');
    return false;
  }
  const interest = hfmV108TransferInterest(player, player.club || clubName, player.leagueIndex ?? leagueIndex);
  const freeAgent = !!player.freeAgent || String(player.club || clubName) === 'Ablösefrei';
  if (interest < 32) {
    state.transferNegotiation = {
      version: 108, stage: 'interest_no', playerId: String(player.id), clubName: player.club || clubName || '', leagueIndex: Number(player.leagueIndex ?? leagueIndex), freeAgent,
      lastMessage: `${player.name} möchte aktuell nicht zu deinem Verein wechseln. Gründe können Vereinsimage, aktueller Wohlfühlfaktor, Rolle beim aktuellen Klub oder Karrierephase sein.`
    };
    state.transferNegotiationOffer = {};
    render();
    return false;
  }
  const seller = hfmV108SellerDemand(player, player.club || clubName, player.leagueIndex ?? leagueIndex);
  const demand = hfmV108ContractDemand(player, player.club || clubName, player.leagueIndex ?? leagueIndex);
  state.transferNegotiation = {
    version: 108,
    stage: freeAgent ? 'player' : 'interest_yes',
    playerId: String(player.id), clubName: player.club || clubName || '', leagueIndex: Number(player.leagueIndex ?? leagueIndex),
    freeAgent, transferList: !!options.transferList, round: 1, maxRounds: 4, clubPatience: 3,
    marketValue: seller.market, sellerAsk: seller.ask, sellerMin: seller.min, sellerStatus: seller.label, agreedFee: freeAgent ? 0 : null,
    playerRound: 1, playerPatience: interest < 50 ? 2 : 3,
    lastMessage: freeAgent ? 'Der Spieler ist ablösefrei. Du verhandelst direkt mit dem Spieler und seinem Berater.' : `${player.name} kann sich einen Wechsel grundsätzlich vorstellen. Zuerst musst du dich aber mit ${player.club || clubName} über die Ablöse einigen.`
  };
  state.transferNegotiationOffer = { fee: seller.ask, years: demand.years, salary: demand.salary, bonus: demand.bonus, role: demand.role, appearanceBonus: 0, goalBonus: 0, releaseClause: 0 };
  render();
  return false;
}
function hfmV108CloseTransferNegotiation() { state.transferNegotiation = null; render(); return false; }
function hfmV108ContinueToClubNegotiation() {
  if (!state.transferNegotiation) return false;
  state.transferNegotiation.stage = 'club';
  state.transferNegotiation.lastMessage = 'Vereinsverhandlung gestartet. Gib eine Ablöse ab. Der Preis hängt stark vom Marktwert, der Vertragslaufzeit und der Rolle des Spielers beim Verkäufer ab.';
  render();
  return false;
}
function hfmV108SetTransferOfferField(field, value) {
  hfmV108EnsureTransferState();
  const offer = state.transferNegotiationOffer || (state.transferNegotiationOffer = {});
  if (field === 'role') offer.role = String(value || 'Rotation');
  else {
    const n = Number(value || 0);
    if (field === 'years') offer.years = Math.max(1, Math.min(5, Math.round(n)));
    if (field === 'salary') offer.salary = Math.max(0, Math.round(n));
    if (field === 'bonus') offer.bonus = Math.max(0, Math.round(n));
    if (field === 'fee') offer.fee = Math.max(0, Math.round(n));
    if (field === 'appearanceBonus') offer.appearanceBonus = Math.max(0, Math.round(n));
    if (field === 'goalBonus') offer.goalBonus = Math.max(0, Math.round(n));
    if (field === 'releaseClause') offer.releaseClause = Math.max(0, Math.round(n));
  }
  render();
  return false;
}
function hfmV108SubmitClubFeeOffer() {
  const neg = state.transferNegotiation;
  if (!neg) return false;
  const player = hfmV107ResolveTransferPlayer(neg.playerId, neg.clubName, neg.leagueIndex);
  if (!player) { state.transferNegotiation = null; render(); return false; }
  const offerFee = Number(state.transferNegotiationOffer?.fee || 0);
  const min = Number(neg.sellerMin || 0);
  if (offerFee < min * 0.6) {
    neg.stage = 'club_failed';
    neg.lastMessage = `${neg.clubName} bricht die Verhandlung ab. Dein Angebot lag deutlich unter der Schmerzgrenze. Frühestens in einigen Wochen kannst du es erneut versuchen.`;
    render();
    return false;
  }
  if (offerFee >= min) {
    const demand = hfmV108ContractDemand(player, neg.clubName, neg.leagueIndex);
    neg.stage = 'player';
    neg.agreedFee = offerFee;
    neg.playerRound = 1;
    neg.lastMessage = `${neg.clubName} akzeptiert ${euro(offerFee)}. Jetzt verhandelst du mit ${player.name} und seinem Berater über Gehalt, Laufzeit, Boni und Rolle.`;
    state.transferNegotiationOffer.years = demand.years;
    state.transferNegotiationOffer.salary = demand.salary;
    state.transferNegotiationOffer.bonus = demand.bonus;
    state.transferNegotiationOffer.role = demand.role;
    render();
    return false;
  }
  neg.clubPatience = Number(neg.clubPatience || 3) - 1;
  if (neg.clubPatience <= 0) {
    neg.stage = 'club_failed';
    neg.lastMessage = `${neg.clubName} hat die Geduld verloren. Die Ablöseverhandlung ist gescheitert.`;
    render();
    return false;
  }
  const newAsk = hfmV108RoundMoney(min + (Number(neg.sellerAsk || min) - min) * 0.55, 10000);
  neg.sellerAsk = Math.max(min, Math.min(Number(neg.sellerAsk || newAsk), newAsk));
  state.transferNegotiationOffer.fee = neg.sellerAsk;
  neg.round = Number(neg.round || 1) + 1;
  neg.lastMessage = `${neg.clubName} lehnt ab, kommt dir aber entgegen. Neue Forderung: ${euro(neg.sellerAsk)}. Geduld: ${neg.clubPatience}/3.`;
  render();
  return false;
}
function hfmV108RoleScore(player, role) {
  const strength = Number(player.strength || 0);
  if (strength >= 75) return role === 'Stammspieler' ? 20 : role === 'Wichtiger Spieler' ? 15 : role === 'Rotation' ? 3 : 0;
  if (Number(player.age || 24) <= 22) return role === 'Talent aufbauen' ? 20 : role === 'Rotation' ? 16 : role === 'Wichtiger Spieler' ? 10 : 7;
  return role === 'Wichtiger Spieler' ? 20 : role === 'Rotation' ? 16 : role === 'Stammspieler' ? 14 : 8;
}
function hfmV108LengthScore(player, years) {
  const age = Number(player.age || 24);
  const y = Number(years || 1);
  const ideal = age <= 22 ? 3 : age >= 31 ? 3 : 4;
  return Math.max(0, 15 - Math.abs(y - ideal) * 5);
}
function hfmV108ContractScore(player, offer, demand) {
  const salaryRatio = Number(offer.salary || 0) / Math.max(1, Number(demand.salary || 1));
  let salaryPts = salaryRatio >= 1 ? Math.min(50, 40 + (salaryRatio - 1) * 22) : Math.max(0, salaryRatio * 40);
  const rolePts = hfmV108RoleScore(player, offer.role || 'Rotation');
  const yearsPts = hfmV108LengthScore(player, offer.years || 1);
  const bonusValue = Number(offer.bonus || 0) + Number(offer.appearanceBonus || 0) * 8 + Number(offer.goalBonus || 0) * 5;
  let bonusPts = Math.min(25, (bonusValue / Math.max(1, Number(demand.bonus || 1))) * 18);
  if (Number(offer.releaseClause || 0) > 0) bonusPts += 5;
  const interest = Number(demand.interest || 50);
  const interestAdj = (interest - 50) / 5;
  return salaryPts + rolePts + yearsPts + bonusPts + interestAdj;
}
function hfmV108SubmitPlayerContractOffer() {
  const neg = state.transferNegotiation;
  if (!neg) return false;
  const player = hfmV107ResolveTransferPlayer(neg.playerId, neg.clubName, neg.leagueIndex);
  if (!player) { state.transferNegotiation = null; render(); return false; }
  const offer = state.transferNegotiationOffer || {};
  const demand = hfmV108ContractDemand(player, neg.clubName, neg.leagueIndex);
  if (Number(offer.salary || 0) < Number(demand.salary || 1) * 0.7) {
    neg.stage = 'player_failed';
    neg.lastMessage = `${player.name} und sein Berater brechen ab. Das Grundgehalt lag zu weit unter der Forderung.`;
    render();
    return false;
  }
  const score = hfmV108ContractScore(player, offer, demand);
  const required = Number(demand.interest || 50) < 50 ? 82 : 75;
  if (score >= required) return hfmV108CommitTransfer(player, offer, neg);
  neg.playerPatience = Number(neg.playerPatience || 3) - 1;
  if (neg.playerPatience <= 0 || Number(neg.playerRound || 1) >= 4) {
    neg.stage = 'player_failed';
    neg.lastMessage = `${player.name} lehnt ab. Das Gesamtpaket war nicht stark genug.`;
    render();
    return false;
  }
  neg.playerRound = Number(neg.playerRound || 1) + 1;
  state.transferNegotiationOffer.salary = hfmV108RoundMoney(Math.max(Number(offer.salary || 0) * 1.1, demand.salary), 1000);
  state.transferNegotiationOffer.bonus = hfmV108RoundMoney(Math.max(Number(offer.bonus || 0) * 1.12, demand.bonus), 5000);
  if (hfmV108RoleScore(player, offer.role) < 12) state.transferNegotiationOffer.role = demand.role || 'Wichtiger Spieler';
  neg.lastMessage = `Gegenforderung: Der Berater will ein besseres Gesamtpaket. Aktuelle Angebotswertung: ${Math.round(score)}/${required}. Geduld: ${neg.playerPatience}/3.`;
  render();
  return false;
}
function hfmV108CommitTransfer(player, offer, neg) {
  const fee = Number(neg.agreedFee || offer.fee || 0);
  const bonus = Number(offer.bonus || 0);
  const total = fee + bonus;
  if (Number(state.money || 0) < total) { alert(`Nicht genug Geld. Sofort benötigt: ${euro(total)}.`); return false; }
  state.money = Number(state.money || 0) - total;
  state.finance.expenseTransfers = Number(state.finance.expenseTransfers || 0) + fee;
  state.finance.expenseSalaries = Number(state.finance.expenseSalaries || 0) + bonus;
  if (typeof hfmV65RemoveFromSourceRoster === 'function') hfmV65RemoveFromSourceRoster(player);
  else if (player.freeAgent) state.transferFreeAgents = (state.transferFreeAgents || []).filter(p => String(p.id) !== String(player.id));
  const nextId = Math.max(0, ...((state.players || []).map(p => Number(p.id) || 0))) + 1;
  const incoming = ensurePlayerSkillProfile({
    ...player, id: nextId, club: ownClubName(), leagueIndex: OWN_LEAGUE_INDEX, youth: false, externalYouth: false, youthScout: false, loan: null,
    contractYears: Math.max(1, Math.min(5, Number(offer.years || 3))), salary: Number(offer.salary || player.salary || 20000), progress: Number(player.progress || 0), rating: 3.0, minutes: 0,
    promisedRole: offer.role || 'Rotation', releaseClause: Number(offer.releaseClause || 0), satisfaction: Math.max(55, Number(player.satisfaction || 60))
  });
  if (typeof hfmV98EnsureCharacterTrait === 'function') hfmV98EnsureCharacterTrait(incoming);
  if (typeof hfmV105EnsureComfortPlayer === 'function') hfmV105EnsureComfortPlayer(incoming);
  incoming.marketValue = hfmV108MarketValue(incoming, ownClubName(), OWN_LEAGUE_INDEX);
  state.players.push(incoming);
  state.watchlist = (state.watchlist || []).filter(p => String(p.id) !== String(player.id));
  state.transferFreeAgents = (state.transferFreeAgents || []).filter(p => String(p.id) !== String(player.id));
  state.transferNegotiation = null;
  if (!Array.isArray(state.aiTransferLog)) state.aiTransferLog = [];
  state.aiTransferLog.unshift({ date: formatGermanDate(currentGameDate()), player: player.name, buyer: ownClubName(), seller: player.club || neg.clubName || 'Ablösefrei', fee, pos: player.pos, age: player.age, reason: 'Transfer des Managers' });
  state.aiTransferLog = state.aiTransferLog.slice(0, 100);
  if (typeof initLineup === 'function') initLineup();
  alert(`${player.name} unterschreibt. Ablöse: ${euro(fee)} · Handgeld/Bonus: ${euro(bonus)} · Vertrag: ${incoming.contractYears} Jahre.`);
  render();
  return true;
}
function hfmV108TransferNegotiationModal() {
  hfmV108EnsureTransferState();
  const neg = state.transferNegotiation;
  if (!neg || Number(neg.version || 0) !== 108) return '';
  const player = hfmV107ResolveTransferPlayer(neg.playerId, neg.clubName, neg.leagueIndex);
  if (!player) return '';
  const offer = state.transferNegotiationOffer || {};
  const interest = hfmV108TransferInterest(player, neg.clubName, neg.leagueIndex);
  const demand = hfmV108ContractDemand(player, neg.clubName, neg.leagueIndex);
  const roles = ['Talent aufbauen','Rotation','Wichtiger Spieler','Stammspieler'];
  const header = `<div class="modalHeader"><div><p class="eyebrow">Transferverhandlung</p><h2>${hfmV68Html(player.name)}</h2></div><button type="button" class="ghost closeButton" onclick="hfmV108CloseTransferNegotiation()">Schließen</button></div>`;
  if (neg.stage === 'interest_no') {
    return `<div class="lineupModalBackdrop lineupModalTop transferNegotiationModalV107" role="dialog" aria-modal="true"><div class="lineupModal">${header}<div class="grid compact"><article class="card"><p>Wechselinteresse</p><h2>${interest}%</h2><span>zu niedrig</span></article><article class="card"><p>Wohlfühlfaktor</p><h2>${typeof hfmV105PlayerComfort === 'function' ? hfmV105PlayerComfort(player) : '?'}</h2><span>aktueller Verein</span></article></div><div class="infoBox">${hfmV68Html(neg.lastMessage)}</div><div class="modalActions"><button class="primary full" onclick="hfmV108CloseTransferNegotiation()">OK</button></div></div></div>`;
  }
  if (neg.stage === 'interest_yes') {
    return `<div class="lineupModalBackdrop lineupModalTop transferNegotiationModalV107" role="dialog" aria-modal="true"><div class="lineupModal">${header}<div class="grid compact"><article class="card"><p>Wechselinteresse</p><h2>${interest}%</h2><span>grundsätzlich offen</span></article><article class="card"><p>Marktwert</p><h2>${euro(neg.marketValue)}</h2><span>dynamisch berechnet</span></article><article class="card"><p>Vereinsstatus</p><h2>${hfmV68Html(neg.sellerStatus)}</h2><span>${hfmV68Html(neg.clubName)}</span></article></div><div class="infoBox">${hfmV68Html(neg.lastMessage)}</div><div class="modalActions"><button class="ghost full" onclick="hfmV108CloseTransferNegotiation()">Abbrechen</button><button class="primary full" onclick="hfmV108ContinueToClubNegotiation()">Mit Verein verhandeln</button></div></div></div>`;
  }
  if (neg.stage === 'club') {
    return `<div class="lineupModalBackdrop lineupModalTop transferNegotiationModalV107" role="dialog" aria-modal="true"><div class="lineupModal">${header}<div class="grid compact"><article class="card"><p>Marktwert</p><h2>${euro(neg.marketValue)}</h2><span>Stärke · Alter · Vertrag · Liga</span></article><article class="card"><p>Forderung</p><h2>${euro(neg.sellerAsk)}</h2><span>${hfmV68Html(neg.sellerStatus)}</span></article><article class="card"><p>Geduld</p><h2>${neg.clubPatience}/3</h2><span>Verein</span></article></div><div class="infoBox">${hfmV68Html(neg.lastMessage)}</div><label class="fieldLabel">Ablöseangebot an ${hfmV68Html(neg.clubName)}</label><input type="number" value="${Number(offer.fee || 0)}" step="10000" onchange="hfmV108SetTransferOfferField('fee', this.value)" /><div class="modalActions"><button class="ghost full" onclick="hfmV108CloseTransferNegotiation()">Abbrechen</button><button class="primary full" onclick="hfmV108SubmitClubFeeOffer()">Ablöse anbieten</button></div></div></div>`;
  }
  if (neg.stage === 'club_failed' || neg.stage === 'player_failed') {
    return `<div class="lineupModalBackdrop lineupModalTop transferNegotiationModalV107" role="dialog" aria-modal="true"><div class="lineupModal">${header}<div class="infoBox">${hfmV68Html(neg.lastMessage)}</div><div class="modalActions"><button class="primary full" onclick="hfmV108CloseTransferNegotiation()">OK</button></div></div></div>`;
  }
  const totalImmediate = Number(neg.agreedFee || 0) + Number(offer.bonus || 0);
  const score = Math.round(hfmV108ContractScore(player, offer, demand));
  const required = demand.interest < 50 ? 82 : 75;
  return `<div class="lineupModalBackdrop lineupModalTop transferNegotiationModalV107" role="dialog" aria-modal="true"><div class="lineupModal">${header}<div class="grid compact"><article class="card"><p>Ablöse</p><h2>${euro(neg.agreedFee || 0)}</h2><span>${neg.freeAgent ? 'ablösefrei' : 'mit Verein geeinigt'}</span></article><article class="card"><p>Sofortkosten</p><h2>${euro(totalImmediate)}</h2><span>Ablöse + Handgeld</span></article><article class="card"><p>Angebotswertung</p><h2>${score}/${required}</h2><span>Gehalt · Rolle · Laufzeit · Boni</span></article></div><div class="infoBox"><b>${hfmV68Html(neg.lastMessage || 'Der Berater wartet auf dein Angebot.')}</b><br>Beraterforderung grob: ${demand.years} Jahre · Gehalt ca. ${euro(demand.salary)} · Handgeld ca. ${euro(demand.bonus)} · Wunschrolle: ${hfmV68Html(demand.role)}.</div><label class="fieldLabel">Vertragsdauer</label><select onchange="hfmV108SetTransferOfferField('years', this.value)">${[1,2,3,4,5].map(y => `<option value="${y}" ${Number(offer.years)==y?'selected':''}>${y} Jahre</option>`).join('')}</select><label class="fieldLabel">Monatsgehalt</label><input type="number" value="${Number(offer.salary || 0)}" step="1000" onchange="hfmV108SetTransferOfferField('salary', this.value)" /><label class="fieldLabel">Handgeld / Unterschriftsbonus</label><input type="number" value="${Number(offer.bonus || 0)}" step="5000" onchange="hfmV108SetTransferOfferField('bonus', this.value)" /><label class="fieldLabel">Auflaufprämie</label><input type="number" value="${Number(offer.appearanceBonus || 0)}" step="500" onchange="hfmV108SetTransferOfferField('appearanceBonus', this.value)" /><label class="fieldLabel">Torprämie / Zu-Null-Bonus</label><input type="number" value="${Number(offer.goalBonus || 0)}" step="500" onchange="hfmV108SetTransferOfferField('goalBonus', this.value)" /><label class="fieldLabel">Ausstiegsklausel</label><input type="number" value="${Number(offer.releaseClause || 0)}" step="10000" onchange="hfmV108SetTransferOfferField('releaseClause', this.value)" /><label class="fieldLabel">Sportliche Rolle</label><select onchange="hfmV108SetTransferOfferField('role', this.value)">${roles.map(r => `<option value="${r}" ${String(offer.role||'')===r?'selected':''}>${r}</option>`).join('')}</select><div class="modalActions"><button class="ghost full" onclick="hfmV108CloseTransferNegotiation()">Abbrechen</button><button class="primary full" onclick="hfmV108SubmitPlayerContractOffer()">Vertragsangebot abgeben</button></div></div></div>`;
}

