function hfmV110StaffAttrLabel(attr) { return HFM_V110_STAFF_ATTR_LABELS[attr] || attr; }
function hfmV110StaffTraitLabel(trait) { return (HFM_V110_STAFF_TRAITS[trait] || HFM_V110_STAFF_TRAITS.BALANCED).label; }
