  state.staffNegotiation = { staffId: String(id), source: found.source, key: found.key || null, salary: targetSalary, years: Math.min(5, Math.max(1, Number(s.contractYears || 2))), signingFee: Math.round(targetSalary * 2 / 1000) * 1000, rounds: 3, message: `${s.name} ist grundsätzlich gesprächsbereit. Sein aktuelles Gehalt liegt bei ${euro(s.salary || 0)}.` };
