window.developAcademyPlayers = developAcademyPlayers;
function hfmV110AgeAndRefreshStaff() {
  hfmV110EnsureStaffState();
  const retired = [];
  function ageOne(s) {
    const age = Number(s.age || 40) + 1;
    let retireChance = 0;
    if (age >= 75) retireChance = 1; else if (age >= 71) retireChance = 0.60; else if (age >= 66) retireChance = 0.25; else if (age >= 60) retireChance = 0.05;
    const roll = (Math.abs(stableHash(`${s.id}-${seasonLabel()}-retire`)) % 1000) / 1000;
    if (roll < retireChance) { retired.push(s); return null; }
    const attrs = { ...(s.attributes || {}) };
    Object.keys(attrs).forEach(k => {
      let delta = age <= 50 ? hfmV110HashRand(`${s.id}-${k}-${seasonLabel()}-grow`, 0, 2) : age >= 60 ? hfmV110HashRand(`${s.id}-${k}-${seasonLabel()}-decline`, -2, 1) : hfmV110HashRand(`${s.id}-${k}-${seasonLabel()}-mid`, 0, 1);
      if (s.role === 'fitness' && age >= 60) delta -= 1;
      attrs[k] = hfmV110Clamp(Number(attrs[k] || 50) + delta);
    });
    const updated = { ...s, age, attributes: attrs, contractYears: Math.max(0, Number(s.contractYears || 1) - 1) };
    updated.strength = hfmV110StaffStrength(updated);
    return updated;
  }
  state.staff = (state.staff || []).map(ageOne).filter(Boolean);
  state.staffMarket = (state.staffMarket || []).map(ageOne).filter(Boolean);
  Object.keys(state.clubStaffCache || {}).forEach(key => { state.clubStaffCache[key] = (state.clubStaffCache[key] || []).map(ageOne).filter(Boolean); });
  retired.forEach(s => { if (hfmV68AddNews) hfmV68AddNews({ category: 'VEREIN', priority: 2, scope: 'inbox', uniqueKey: `staff-retire-${s.id}-${seasonLabel()}`, title_template: 'Mitarbeiter geht in Ruhestand', body_template: `${s.name} (${hfmV110StaffRoleLabel(s.role)}, ${s.age} Jahre) beendet seine Karriere.`, data: {} }); });
  hfmV110EnsureStaffState();
  hfmV110EnsureStaffMarket();
}
