/* === v113 Mitarbeiter-Fixes: Fremdverein-Klick, Marktfilter, Vertragsverwaltung === */
function hfmV113StaffActionId(id) { return String(id || '').replace(/'/g, "\\'"); }
function hfmV113Num(v, fallback = 0) { const n = Number(v); return Number.isFinite(n) ? n : fallback; }
function hfmV113StaffMonthsLeft(s) { return Math.max(0, Math.round(hfmV113Num(s?.contractYears, 0) * 12)); }
function hfmV113StaffReleaseCost(s) { return hfmV113StaffMonthsLeft(s) * Math.max(0, hfmV113Num(s?.salary, 0)); }
