  const def = HFM_V110_STAFF_ROLES[s.role] || HFM_V110_STAFF_ROLES.assistant;
  const attrRows = def.slots.map(k => `<div class="financeRow"><span>${hfmV110StaffAttrLabel(k)}</span><strong>${Number(s.attributes?.[k] || 0)}</strong></div>`).join('');
  const canHire = found.source !== 'own';
