/* === v115: Suche erst nach Klick auf "Jetzt suchen" (Spieler + Mitarbeiter) === */
function hfmV115DefaultMarketSearch() {
  return { name: '', position: 'Alle', maxAge: '', minStrength: '', minTalent: '', minValue: '', maxValue: '' };
}
function hfmV115EnsurePlayerSearchState() {
  if (!state.marketSearchDraft || typeof state.marketSearchDraft !== 'object') {
    state.marketSearchDraft = { ...hfmV115DefaultMarketSearch(), ...(state.marketSearch || {}) };
  }
  if (!state.marketSearchApplied || typeof state.marketSearchApplied !== 'object') {
    state.marketSearchApplied = null;
  }
  if (!state.marketSearch || typeof state.marketSearch !== 'object') {
    state.marketSearch = { ...hfmV115DefaultMarketSearch(), ...state.marketSearchDraft };
  }
}
function hfmV115FieldValue(obj, field) {
  return String((obj && obj[field]) || '').replace(/"/g, '&quot;');
}
function hfmV115SetMarketSearchDraft(field, value) {
  hfmV115EnsurePlayerSearchState();
  state.marketSearchDraft[field] = value;
  if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
  return false;
}
window.setMarketSearchField = hfmV115SetMarketSearchDraft;
setMarketSearchField = hfmV115SetMarketSearchDraft;

function hfmV115RunMarketSearch() {
  hfmV115EnsurePlayerSearchState();
  state.marketSearchApplied = { ...hfmV115DefaultMarketSearch(), ...state.marketSearchDraft };
  state.marketSearch = { ...state.marketSearchApplied };
  state.marketSearchHasSearched = true;
  if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
  render();
  return false;
}
window.hfmV115RunMarketSearch = hfmV115RunMarketSearch;

const hfmV115MarketSearchResultsBase = marketSearchResults;
marketSearchResults = function() {
  hfmV115EnsurePlayerSearchState();
  const old = state.marketSearch;
  state.marketSearch = { ...hfmV115DefaultMarketSearch(), ...(state.marketSearchApplied || state.marketSearchDraft || {}) };
  try { return hfmV115MarketSearchResultsBase(); }
  finally { state.marketSearch = old; }
};

function hfmV115MarketSearchResultsHtml() {
  hfmV115EnsurePlayerSearchState();
  if (!state.marketSearchHasSearched || !state.marketSearchApplied) {
    return '<div class="infoBox">Stelle zuerst deine Filter ein und klicke dann auf <strong>Jetzt suchen</strong>.</div>';
  }
  const results = marketSearchResults().map(p => marketPlayerRow(p, { showOverall: true })).join('');
  return results || '<div class="infoBox">Keine passenden Spieler gefunden.</div>';
}

playerSearchView = function() {
  hfmV115EnsurePlayerSearchState();
  const f = state.marketSearchDraft;
  const positions = ['Alle','TW','RV','IV','LV','DM','ZM','OM','RM','LM','RA','LA','ST'];
  const saved = (state.savedMarketSearches || []).map((entry, index) => `<div class="financeRow"><span>${entry.label}</span><strong><button type="button" class="ghost smallButton" onclick="loadMarketSearch(${index})">Laden</button> <button type="button" class="ghost smallButton" onclick="deleteMarketSearch(${index})">Löschen</button></strong></div>`).join('');
  return `<section class="panel"><p class="eyebrow">Transfers · Spielersuche</p><h2>Spielersuche</h2><div class="infoBox">Durchsuche Spieler aller Vereine und Ligen. Die Suche startet erst, wenn du auf <strong>Jetzt suchen</strong> klickst. Dadurch kannst du alle Filter in Ruhe eingeben, ohne dass die Ergebnisliste live neu lädt.</div><div class="searchGrid"><label class="fieldLabel">Name<input value="${hfmV115FieldValue(f, 'name')}" oninput="setMarketSearchField('name', this.value)" placeholder="Spielername" autocomplete="off" /></label><label class="fieldLabel">Position<select onchange="setMarketSearchField('position', this.value)">${positions.map(pos => `<option value="${pos}" ${f.position === pos ? 'selected' : ''}>${pos}</option>`).join('')}</select></label><label class="fieldLabel">Max. Alter<input type="number" inputmode="numeric" value="${hfmV115FieldValue(f, 'maxAge')}" oninput="setMarketSearchField('maxAge', this.value)" placeholder="z.B. 24" /></label><label class="fieldLabel">Min. Stärke<input type="number" inputmode="numeric" value="${hfmV115FieldValue(f, 'minStrength')}" oninput="setMarketSearchField('minStrength', this.value)" placeholder="z.B. 60" /></label><label class="fieldLabel">Min. Talent<input type="number" inputmode="numeric" value="${hfmV115FieldValue(f, 'minTalent')}" min="1" max="5" oninput="setMarketSearchField('minTalent', this.value)" placeholder="1-5" /></label><label class="fieldLabel">Min. Marktwert<input type="number" inputmode="numeric" value="${hfmV115FieldValue(f, 'minValue')}" oninput="setMarketSearchField('minValue', this.value)" placeholder="z.B. 100000" /></label><label class="fieldLabel">Max. Marktwert<input type="number" inputmode="numeric" value="${hfmV115FieldValue(f, 'maxValue')}" oninput="setMarketSearchField('maxValue', this.value)" placeholder="z.B. 500000" /></label></div><div class="playerActions"><button type="button" class="primary" onclick="return hfmV115RunMarketSearch()">Jetzt suchen</button><button type="button" class="ghost" onclick="saveMarketSearch()">Filter speichern</button><button type="button" class="ghost" onclick="clearMarketSearch()">Filter zurücksetzen</button></div>${saved ? `<h3>Gespeicherte Filter</h3><div class="financeGrid">${saved}</div>` : ''}<h3>Suchergebnisse</h3><div class="playerList" id="marketSearchResultsList">${hfmV115MarketSearchResultsHtml()}</div></section>`;
};

saveMarketSearch = function() {
  hfmV115EnsurePlayerSearchState();
  const label = prompt('Name für diesen Suchfilter:', `Filter ${(state.savedMarketSearches || []).length + 1}`);
  if (!label) return;
  if (!Array.isArray(state.savedMarketSearches)) state.savedMarketSearches = [];
  state.savedMarketSearches.push({ label, filter: { ...state.marketSearchDraft } });
  if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
  render();
};
window.saveMarketSearch = saveMarketSearch;

loadMarketSearch = function(index) {
  const saved = (state.savedMarketSearches || [])[Number(index)];
  if (!saved) return;
  hfmV115EnsurePlayerSearchState();
  state.marketSearchDraft = { ...hfmV115DefaultMarketSearch(), ...saved.filter };
  state.marketSearchHasSearched = false;
  state.marketSearchApplied = null;
  if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
  render();
};
window.loadMarketSearch = loadMarketSearch;

clearMarketSearch = function() {
  state.marketSearchDraft = hfmV115DefaultMarketSearch();
  state.marketSearchApplied = null;
  state.marketSearch = { ...state.marketSearchDraft };
  state.marketSearchHasSearched = false;
  if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
  render();
};
window.clearMarketSearch = clearMarketSearch;

function hfmV115DefaultStaffMarketDraft() {
  return { role: state.staffMarketRole || 'all', minAge: '', maxAge: '', minStrength: '', maxStrength: '', minSalary: '', maxSalary: '' };
}
function hfmV115EnsureStaffSearchState() {
  if (!state.staffMarketDraft || typeof state.staffMarketDraft !== 'object') {
    state.staffMarketDraft = {
      role: state.staffMarketRole || 'all',
      minAge: state.staffMarketMinAge === undefined ? '' : state.staffMarketMinAge,
      maxAge: state.staffMarketMaxAge === undefined ? '' : state.staffMarketMaxAge,
      minStrength: state.staffMarketMinStrength === undefined ? '' : state.staffMarketMinStrength,
      maxStrength: state.staffMarketMaxStrength === undefined ? '' : state.staffMarketMaxStrength,
      minSalary: state.staffMarketMinSalary === undefined ? '' : state.staffMarketMinSalary,
      maxSalary: state.staffMarketMaxSalary === undefined ? '' : state.staffMarketMaxSalary
    };
  }
  if (!state.staffMarketApplied || typeof state.staffMarketApplied !== 'object') state.staffMarketApplied = null;
}
function hfmV115SetStaffMarketDraft(field, value) {
  hfmV115EnsureStaffSearchState();
  state.staffMarketDraft[field] = value === null || typeof value === 'undefined' ? '' : value;
  if (field === 'role') state.staffMarketRole = state.staffMarketDraft.role || 'all';
  if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
  return false;
}
window.hfmV115SetStaffMarketDraft = hfmV115SetStaffMarketDraft;
function hfmV115RunStaffMarketSearch() {
  hfmV115EnsureStaffSearchState();
  const d = { ...hfmV115DefaultStaffMarketDraft(), ...state.staffMarketDraft };
  state.staffMarketApplied = { ...d };
  state.staffMarketRole = d.role || 'all';
  state.staffMarketMinAge = d.minAge;
  state.staffMarketMaxAge = d.maxAge;
  state.staffMarketMinStrength = d.minStrength;
  state.staffMarketMaxStrength = d.maxStrength;
  state.staffMarketMinSalary = d.minSalary;
  state.staffMarketMaxSalary = d.maxSalary;
  state.staffMarketHasSearched = true;
  if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
  render();
  return false;
}
window.hfmV115RunStaffMarketSearch = hfmV115RunStaffMarketSearch;
function hfmV115ResetStaffMarketSearch() {
  state.staffMarketDraft = hfmV115DefaultStaffMarketDraft();
  state.staffMarketApplied = null;
  state.staffMarketHasSearched = false;
  state.staffMarketRole = state.staffMarketDraft.role || 'all';
  if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
  render();
  return false;
}
window.hfmV115ResetStaffMarketSearch = hfmV115ResetStaffMarketSearch;

hfmV113SetStaffMarketFilter = function(field, value) {
  const map = {
    staffMarketMinAge: 'minAge', staffMarketMaxAge: 'maxAge',
    staffMarketMinStrength: 'minStrength', staffMarketMaxStrength: 'maxStrength',
    staffMarketMinSalary: 'minSalary', staffMarketMaxSalary: 'maxSalary'
  };
  return hfmV115SetStaffMarketDraft(map[field] || field, value);
};
window.hfmV113SetStaffMarketFilter = hfmV113SetStaffMarketFilter;

hfmV110StaffMarketView = function() {
  hfmV110NormalizeStaff();
  hfmV115EnsureStaffSearchState();
  const d = { ...hfmV115DefaultStaffMarketDraft(), ...state.staffMarketDraft };
  const role = d.role || 'all';
  const toNumOrEmpty = v => (v === '' || v === null || typeof v === 'undefined') ? '' : hfmV113Num(v, '');
  const minAge = toNumOrEmpty(d.minAge), maxAge = toNumOrEmpty(d.maxAge);
  const minStrength = toNumOrEmpty(d.minStrength), maxStrength = toNumOrEmpty(d.maxStrength);
  const minSalary = toNumOrEmpty(d.minSalary), maxSalary = toNumOrEmpty(d.maxSalary);
  const options = ['all'].concat(hfmV110RequiredStaffRoles()).map(r => `<option value="${r}" ${role === r ? 'selected' : ''}>${r === 'all' ? 'Alle Rollen' : hfmV110StaffRoleLabel(r)}</option>`).join('');
  let resultsHtml = '<div class="infoBox">Stelle zuerst deine Filter ein und klicke dann auf <strong>Jetzt suchen</strong>.</div>';
  if (state.staffMarketHasSearched && state.staffMarketApplied) {
    const a = { ...hfmV115DefaultStaffMarketDraft(), ...state.staffMarketApplied };
    const ar = a.role || 'all';
    const aminAge = toNumOrEmpty(a.minAge), amaxAge = toNumOrEmpty(a.maxAge);
    const aminStrength = toNumOrEmpty(a.minStrength), amaxStrength = toNumOrEmpty(a.maxStrength);
    const aminSalary = toNumOrEmpty(a.minSalary), amaxSalary = toNumOrEmpty(a.maxSalary);
    const list = (state.staffMarket || []).filter(s => {
      const strength = hfmV110StaffStrength(s), age = hfmV113Num(s.age), salary = hfmV113Num(s.salary);
      if (ar !== 'all' && s.role !== ar) return false;
      if (aminAge !== '' && age < aminAge) return false;
      if (amaxAge !== '' && age > amaxAge) return false;
      if (aminStrength !== '' && strength < aminStrength) return false;
      if (amaxStrength !== '' && strength > amaxStrength) return false;
      if (aminSalary !== '' && salary < aminSalary) return false;
      if (amaxSalary !== '' && salary > amaxSalary) return false;
      return true;
    });
    resultsHtml = list.map(s => hfmV110StaffRow(s, 'market')).join('') || '<div class="infoBox">Aktuell keine passenden Mitarbeiter auf dem Markt.</div>';
  }
  return `<div class="infoBox">Arbeitslose Mitarbeiter können wie Spieler verpflichtet werden. Die Suche startet erst nach Klick auf <strong>Jetzt suchen</strong>, damit Filtereingaben keine Live-Suche auslösen.</div><div class="formGrid"><label><span>Rolle</span><select onchange="hfmV115SetStaffMarketDraft('role', this.value)">${options}</select></label><label><span>Alter von</span><input type="number" value="${minAge}" placeholder="z.B. 25" oninput="hfmV115SetStaffMarketDraft('minAge', this.value)"></label><label><span>Alter bis</span><input type="number" value="${maxAge}" placeholder="z.B. 55" oninput="hfmV115SetStaffMarketDraft('maxAge', this.value)"></label><label><span>Stärke von</span><input type="number" value="${minStrength}" placeholder="z.B. 60" oninput="hfmV115SetStaffMarketDraft('minStrength', this.value)"></label><label><span>Stärke bis</span><input type="number" value="${maxStrength}" placeholder="z.B. 90" oninput="hfmV115SetStaffMarketDraft('maxStrength', this.value)"></label><label><span>Gehalt von</span><input type="number" value="${minSalary}" placeholder="€ / Monat" step="100" oninput="hfmV115SetStaffMarketDraft('minSalary', this.value)"></label><label><span>Gehalt bis</span><input type="number" value="${maxSalary}" placeholder="€ / Monat" step="100" oninput="hfmV115SetStaffMarketDraft('maxSalary', this.value)"></label></div><div class="playerActions"><button type="button" class="primary" onclick="return hfmV115RunStaffMarketSearch()">Jetzt suchen</button><button type="button" class="ghost" onclick="return hfmV115ResetStaffMarketSearch()">Filter zurücksetzen</button></div><div class="playerList">${resultsHtml}</div>`;
};
window.hfmV110StaffMarketView = hfmV110StaffMarketView;

hfmV114FindStaffForVacancy = function(role) {
  const r = String(role || 'all');
  state.staffSection = 'market';
  state.staffMarketDraft = { ...hfmV115DefaultStaffMarketDraft(), role: r };
  state.staffMarketApplied = null;
  state.staffMarketHasSearched = false;
  state.staffMarketRole = r;
  if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
  render();
  return false;
};
window.hfmV114FindStaffForVacancy = hfmV114FindStaffForVacancy;

try { if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave(); } catch (err) { console.warn(err); }

/* === v116: Eigene Spieler verkaufen/verleihen, Vertrag aufloesen und Kalender-Endlosfix === */
function hfmV116Num(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}
function hfmV116OwnPlayer(playerOrId) {
  const id = typeof playerOrId === 'object' ? Number(playerOrId && playerOrId.id) : Number(playerOrId);
  return (state.players || []).find(p => Number(p.id) === id) || null;
}
function hfmV116ListingLabel(player) {
  if (!player || !player.transferListed) return 'nicht gelistet';
  if (player.transferMode === 'loan') return `zur Leihe angeboten${player.askingPrice ? ` · Wunsch ${euro(player.askingPrice)}` : ''}`;
  return `zum Verkauf angeboten${player.askingPrice ? ` · Wunsch ${euro(player.askingPrice)}` : ''}`;
}
function hfmV116DefaultAsk(player) {
  const market = typeof hfmV108MarketValue === 'function' ? hfmV108MarketValue(player, ownClubName(), OWN_LEAGUE_INDEX) : hfmV68EstimatedPlayerValue(player);
  return Math.max(10000, Math.round(Number(market || player.marketValue || 100000) / 10000) * 10000);
}
function hfmV116OpenOwnPlayerSaleDialog(playerId) {
  const p = hfmV116OwnPlayer(playerId);
  if (!p) return false;
  state.ownPlayerSaleDialog = {
    playerId: Number(p.id),
    mode: p.transferMode || 'sale',
    askingPrice: Number(p.askingPrice || hfmV116DefaultAsk(p)),
    message: p.transferListed ? 'Der Spieler steht bereits auf der Transferliste.' : 'Lege fest, ob du den Spieler verkaufen oder verleihen möchtest.'
  };
  render();
  return false;
}
window.hfmV116OpenOwnPlayerSaleDialog = hfmV116OpenOwnPlayerSaleDialog;
function hfmV116CloseOwnPlayerSaleDialog() { state.ownPlayerSaleDialog = null; render(); return false; }
window.hfmV116CloseOwnPlayerSaleDialog = hfmV116CloseOwnPlayerSaleDialog;
function hfmV116SetOwnSaleField(field, value) {
  if (!state.ownPlayerSaleDialog) return false;
  if (field === 'mode') state.ownPlayerSaleDialog.mode = String(value || 'sale') === 'loan' ? 'loan' : 'sale';
  if (field === 'askingPrice') state.ownPlayerSaleDialog.askingPrice = Math.max(0, Math.round(hfmV116Num(value, 0)));
  render();
  return false;
}
window.hfmV116SetOwnSaleField = hfmV116SetOwnSaleField;
function hfmV116ConfirmOwnSaleListing() {
  const d = state.ownPlayerSaleDialog;
  const p = d ? hfmV116OwnPlayer(d.playerId) : null;
  if (!p) { state.ownPlayerSaleDialog = null; render(); return false; }
  const mode = String(d.mode || 'sale') === 'loan' ? 'loan' : 'sale';
  if (mode === 'loan' && hfmV116Num(p.contractYears, 0) <= 1) {
    alert('Dieser Spieler kann nicht verliehen werden, weil seine Vertragslaufzeit nur noch 1 Jahr oder weniger betraegt. Verleihe sind nur bei mehr als 1 Jahr Restvertrag moeglich.');
    return false;
  }
  p.transferListed = true;
  p.onTransferList = true;
  p.listed = true;
  p.transferMode = mode;
  p.askingPrice = Math.max(0, Math.round(hfmV116Num(d.askingPrice, hfmV116DefaultAsk(p))));
  p.transferListedWeek = Number(state.week || 0);
  p.transferListingSeason = typeof seasonLabel === 'function' ? seasonLabel() : '';
  state.ownPlayerSaleDialog = null;
  if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
  alert(`${p.name} wurde ${mode === 'loan' ? 'zur Leihe' : 'zum Verkauf'} auf die Transferliste gesetzt. Andere Vereine koennen nun Angebote machen, muessen aber nicht exakt deine Wunschsumme bieten.`);
  render();
  return false;
}
window.hfmV116ConfirmOwnSaleListing = hfmV116ConfirmOwnSaleListing;
function hfmV116RemoveOwnPlayerFromTransferList(playerId) {
  const p = hfmV116OwnPlayer(playerId);
  if (!p) return false;
  if (!confirm(`${p.name} von der Transferliste nehmen?`)) return false;
  p.transferListed = false;
  p.onTransferList = false;
  p.listed = false;
  p.transferMode = null;
  p.askingPrice = 0;
  p.transferListedWeek = null;
  if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
  render();
  return false;
}
window.hfmV116RemoveOwnPlayerFromTransferList = hfmV116RemoveOwnPlayerFromTransferList;
releasePlayerContract = function(playerId) {
  const player = hfmV116OwnPlayer(playerId);
  if (!player) return false;
  const years = Math.max(0, hfmV116Num(player.contractYears, 0));
  const compensation = Math.round((hfmV116Num(player.salary, 20000) * years * 12) / 1000) * 1000;
  if (!confirm(`${player.name} Vertrag aufloesen?\n\nRestgehalt sofort faellig: ${euro(compensation)}\nDer Spieler verlaesst den Verein sofort.`)) return false;
  if (hfmV116Num(state.money, 0) < compensation) { alert('Nicht genug Geld fuer die Vertragsaufloesung.'); return false; }
  state.money = hfmV116Num(state.money, 0) - compensation;
  state.finance = state.finance || {};
  state.finance.expenseSalaries = hfmV116Num(state.finance.expenseSalaries, 0) + compensation;
  state.players = (state.players || []).filter(p => Number(p.id) !== Number(player.id));
  Object.keys(state.lineup || {}).forEach(slot => { if (Number(state.lineup[slot]) === Number(player.id)) state.lineup[slot] = null; });
  Object.keys(state.bench || {}).forEach(slot => { if (Number(state.bench[slot]) === Number(player.id)) state.bench[slot] = null; });
  if (state.playerProfile && Number(state.playerProfile.id) === Number(player.id)) state.playerProfile = null;
  if (typeof initLineup === 'function') initLineup();
  if (typeof hfmV77SilentSave === 'function') hfmV77SilentSave();
  render();
  return false;
};
window.releasePlayerContract = releasePlayerContract;
function hfmV116OwnPlayerTransferButtons(player) {
  if (!player) return '';
  const listed = !!player.transferListed;
  const sellButton = listed
    ? `<button type="button" class="ghost full" onclick="return hfmV116RemoveOwnPlayerFromTransferList(${Number(player.id)})">Spieler von Transferliste nehmen</button>`
    : `<button type="button" class="primary full" onclick="return hfmV116OpenOwnPlayerSaleDialog(${Number(player.id)})">Spieler verkaufen</button>`;
  return `${sellButton}<button type="button" class="ghost dangerButton full" onclick="return releasePlayerContract(${Number(player.id)})">Vertrag aufloesen</button>`;
}
function hfmV116OwnPlayerSaleDialogHtml() {
  const d = state.ownPlayerSaleDialog;
  if (!d) return '';
  const p = hfmV116OwnPlayer(d.playerId);
  if (!p) return '';
  const market = hfmV116DefaultAsk(p);
  const loanDisabled = hfmV116Num(p.contractYears, 0) <= 1;
  const mode = loanDisabled && d.mode === 'loan' ? 'sale' : String(d.mode || 'sale');
  return `<div class="lineupModalBackdrop lineupModalTop" role="dialog" aria-modal="true"><div class="lineupModal"><div class="modalHeader"><div><p class="eyebrow">Spieler abgeben</p><h2>${hfmV68Html(p.name)}</h2></div><button type="button" class="ghost closeButton" onclick="return hfmV116CloseOwnPlayerSaleDialog()">Schliessen</button></div><div class="grid compact"><article class="card"><p>Marktwert</p><h2>${euro(market)}</h2><span>dynamische Schaetzung</span></article><article class="card"><p>Vertrag</p><h2>${hfmV116Num(p.contractYears,0)} Jahre</h2><span>Leihe nur bei mehr als 1 Jahr</span></article><article class="card"><p>Status</p><h2>${mode === 'loan' ? 'Leihe' : 'Verkauf'}</h2><span>${hfmV116ListingLabel(p)}</span></article></div><div class="infoBox">Andere Vereine koennen Angebote machen, aber nicht zwingend zu deiner Wunschsumme. Bei gelisteten Spielern ist die Angebotswahrscheinlichkeit deutlich hoeher. Danach kann weiter verhandelt werden.</div><label class="fieldLabel">Art</label><select onchange="hfmV116SetOwnSaleField('mode', this.value)"><option value="sale" ${mode==='sale'?'selected':''}>Spieler verkaufen</option><option value="loan" ${mode==='loan'?'selected':''} ${loanDisabled?'disabled':''}>Spieler verleihen${loanDisabled?' - nicht moeglich, Vertrag zu kurz':''}</option></select><label class="fieldLabel">Gewuenschte ${mode === 'loan' ? 'Leihgebuehr' : 'Verkaufssumme'}</label><input type="number" value="${hfmV116Num(d.askingPrice, market)}" step="10000" onchange="hfmV116SetOwnSaleField('askingPrice', this.value)" /><div class="modalActions"><button type="button" class="ghost full" onclick="return hfmV116CloseOwnPlayerSaleDialog()">Abbrechen</button><button type="button" class="primary full" onclick="return hfmV116ConfirmOwnSaleListing()">Jetzt ${mode === 'loan' ? 'zur Leihe anbieten' : 'verkaufen'}</button></div></div></div>`;
}
window.hfmV116OwnPlayerSaleDialogHtml = hfmV116OwnPlayerSaleDialogHtml;

const hfmV116PlayerProfileModalBase = playerProfileModal;
playerProfileModal = function() {
  const raw = state.playerProfile;
  if (!raw) return '';
  const own = typeof hfmV87IsOwnPlayer === 'function' ? hfmV87IsOwnPlayer(raw) : !!hfmV116OwnPlayer(raw.id);
  if (!own) return hfmV116PlayerProfileModalBase();
  const traited = typeof hfmV98EnsureCharacterTrait === 'function' ? hfmV98EnsureCharacterTrait(raw) : raw;
  const p = typeof hfmV105EnsureComfortPlayer === 'function' ? hfmV105EnsureComfortPlayer(traited) : traited;
  state.playerProfile = p;
  const position = positionText(p);
  const characterBlock = typeof hfmV98TraitProfileHtml === 'function' ? hfmV98TraitProfileHtml(p) : '';
  const details = typeof skillBars === 'function' ? skillBars(p) : '';
  const history = typeof hfmV100ProfileHistory === 'function' ? hfmV100ProfileHistory(p) : (typeof hfmV87ProfileHistory === 'function' ? hfmV87ProfileHistory(p) : '');
  const comfort = typeof hfmV105ComfortBar === 'function' ? hfmV105ComfortBar(p) : '';
  const transferStatus = p.transferListed ? `<div class="infoBox"><b>Transferstatus:</b> ${hfmV116ListingLabel(p)}. Bei gelisteten Spielern ist die Chance auf Angebote anderer Vereine deutlich hoeher.</div>` : '';
  return `<div class="lineupModalBackdrop" role="dialog" aria-modal="true"><div class="lineupModal playerProfileModal"><div class="modalHeader"><div><p class="eyebrow">Spielerprofil</p><h2>${hfmV68Html(p.name)}</h2></div><button type="button" class="ghost closeButton" onclick="closePlayerProfile()">Schliessen</button></div><div class="grid compact"><article class="card"><p>Allgemein</p><h2>${position}</h2><span>${hfmV116Num(p.age,0)} Jahre · ${ownClubName()}</span></article><article class="card"><p>Gesamtstaerke</p><h2>${hfmV116Num(p.strength,0)}</h2><span class="stars">${stars(p.talent)}</span></article><article class="card"><p>Marktwert</p><h2>${euro(p.marketValue || hfmV116DefaultAsk(p))}</h2><span>${hfmV116ListingLabel(p)}</span></article><article class="card"><p>Vertrag</p><h2>${hfmV116Num(p.contractYears,0)} Jahre</h2><span>Gehalt ${euro(p.salary || 0)}</span></article></div>${comfort}${transferStatus}${characterBlock}${details}${history}<div class="modalActions"><button type="button" class="ghost full" onclick="closePlayerProfile(); goTo('team','lineup')">Zur Aufstellung</button><button type="button" class="primary full" onclick="closePlayerProfile(); goTo('team','contracts')">Zur Vertragsansicht</button>${hfmV116OwnPlayerTransferButtons(p)}</div></div></div>${typeof hfmV105ComfortDetailsModal === 'function' ? hfmV105ComfortDetailsModal() : ''}${hfmV116OwnPlayerSaleDialogHtml()}`;
};
window.playerProfileModal = playerProfileModal;

const hfmV116ContractViewBase = contractView;
contractView = function() {
  const dir = state.contractSort || 'asc';
  const sorted = [...(state.players || [])].sort((a,b) => {
    const byYears = hfmV116Num(a.contractYears,0) - hfmV116Num(b.contractYears,0);
    return dir === 'desc' ? -byYears : byYears;
  });
  const rows = sorted.map(player => {
    const status = contractWillingness(player);
    const expireText = hfmV116Num(player.contractYears,0) <= 1 ? 'laeuft bald aus' : `${hfmV116Num(player.contractYears,0)} Jahre Restlaufzeit`;
    const retirement = player.retiring ? '<span>Karriereende geplant</span>' : '';
    const sellButton = player.transferListed
      ? `<button type="button" class="ghost" onclick="return hfmV116RemoveOwnPlayerFromTransferList(${Number(player.id)})">Von Transferliste nehmen</button>`
      : `<button type="button" class="ghost" onclick="return hfmV116OpenOwnPlayerSaleDialog(${Number(player.id)})">Spieler verkaufen</button>`;
    return `<div class="player contractPlayer"><div class="playerTop clickablePlayer" onclick="openOwnPlayerProfile(${Number(player.id)})"><strong>${hfmV68Html(player.name)}</strong><span>${positionText(player)} · ${hfmV116Num(player.age,0)} Jahre</span></div>${typeof contractBar === 'function' ? contractBar(player.contractYears) : ''}<div class="meta"><span>Vertrag: ${expireText}</span><span>Gehalt ${euro(player.salary || 0)}</span><span>Wohlfühlfaktor: ${typeof hfmV105PlayerComfort === 'function' ? hfmV105PlayerComfort(player) : playerSatisfaction(player)}/100</span><span>${hfmV116ListingLabel(player)}</span><span>${status.reason || ''}</span>${retirement}</div><div class="playerActions"><button type="button" class="primary" ${status.ok ? '' : 'disabled'} onclick="openContractExtension(${Number(player.id)})">Vertrag verlaengern</button>${sellButton}<button type="button" class="ghost dangerButton" onclick="return releasePlayerContract(${Number(player.id)})">Vertrag aufloesen</button></div></div>`;
  }).join('');
  const free = typeof hfmV91FreeAgentListHtml === 'function' ? hfmV91FreeAgentListHtml() : '';
  return `<section class="panel"><p class="eyebrow">Team · Vertragsansicht</p><h2>Vertraege & Laufzeiten</h2><div class="sectionHeader"><h3>Sortierung</h3><select onchange="setContractSort(this.value)"><option value="asc" ${dir==='asc'?'selected':''}>Vertragslaenge aufsteigend</option><option value="desc" ${dir==='desc'?'selected':''}>Vertragslaenge absteigend</option></select></div><div class="playerList">${rows || '<div class="infoBox">Keine Spieler im Kader.</div>'}</div><h3>Abloesefreie Transferliste</h3><div class="leagueList">${free}</div>${contractNegotiationModal()}${playerProfileModal()}${hfmV116OwnPlayerSaleDialogHtml()}</section>`;
};
window.contractView = contractView;

const hfmV116MaybeGenerateOfferBase = typeof hfmV108MaybeGenerateOfferForOwnPlayer === 'function' ? hfmV108MaybeGenerateOfferForOwnPlayer : null;
hfmV108MaybeGenerateOfferForOwnPlayer = function() {
  if (typeof hfmV108EnsureTransferState === 'function') hfmV108EnsureTransferState();
  if (typeof hfmV65IsTransferWindow === 'function' && !hfmV65IsTransferWindow(currentGameDate())) return null;
  const listed = (state.players || []).filter(p => !p.youth && p.loan !== 'verliehen' && p.transferListed);
  if (listed.length && typeof hfmV68AddNews === 'function') {
    const key = `${seasonLabel()}:${state.week}:listed-own-offer`;
    if (!(state.transferOutOfferLocks || []).includes(key)) {
      state.transferOutOfferLocks = state.transferOutOfferLocks || [];
      state.transferOutOfferLocks.push(key);
      const seed = stableHash(`${key}-${ownClubName()}`);
      const p = listed[seed % listed.length];
      const chance = p.transferMode === 'loan' ? 0.55 : 0.68;
      if (((seed % 1000) / 1000) < chance) {
        const clubs = typeof hfmV65AiClubUniverse === 'function' ? hfmV65AiClubUniverse(12) : [];
        const buyer = clubs[(seed + 5) % Math.max(1, clubs.length)] || { club: 'FC Interessent', leagueIndex: OWN_LEAGUE_INDEX };
        const ask = hfmV116Num(p.askingPrice, hfmV116DefaultAsk(p));
        const market = hfmV116DefaultAsk(p);
        let fee = p.transferMode === 'loan' ? ask * (0.55 + (seed % 40) / 100) : ask * (0.72 + (seed % 50) / 100);
        if (ask <= 0) fee = market * (p.transferMode === 'loan' ? 0.12 : 0.82);
        fee = hfmV108RoundMoney(Math.max(10000, fee), 10000);
        hfmV68AddNews({ category: 'TRANSFER', priority: 1, scope: 'inbox', sender_id: buyer.club, subject_ids: [p.id, buyer.club], requires_action: true, action_type: 'TRANSFER_OFFER', uniqueKey: `v116-listed-offer-${seasonLabel()}-${state.week}-${p.id}-${buyer.club}`, title_template: 'TRANSFER_OFFER_TITLE', body_template: 'TRANSFER_OFFER_BODY', data: { PLAYER_ID: p.id, PLAYER_NAME: p.name, BUYER: buyer.club, FEE: euro(fee), FEE_VALUE: fee, MAX_FEE_VALUE: hfmV108RoundMoney(Math.max(fee * 1.28, ask * 1.05), 10000), MODE: p.transferMode || 'sale', ASKING_PRICE: ask } });
        return { player: p.name, buyer: buyer.club, fee, listed: true };
      }
    }
  }
  return hfmV116MaybeGenerateOfferBase ? hfmV116MaybeGenerateOfferBase() : null;
};
window.hfmV108MaybeGenerateOfferForOwnPlayer = hfmV108MaybeGenerateOfferForOwnPlayer;

const hfmV116ResolveNewsBase = hfmV68ResolveNewsAction;
hfmV68ResolveNewsAction = function(id, action) {
  const news = (state.newsItems || []).find(n => n.id === id);
  if (news && news.action_type === 'TRANSFER_OFFER' && action === 'accept') {
    const p = hfmV116OwnPlayer(news.data && news.data.PLAYER_ID);
    if (p && news.data && news.data.MODE === 'loan') {
      const fee = hfmV116Num(news.data.FEE_VALUE, 0);
      p.loan = 'verliehen';
      p.loanedTo = news.data.BUYER || 'anderer Verein';
      p.transferListed = false; p.onTransferList = false; p.listed = false; p.transferMode = null; p.askingPrice = 0;
      state.money = hfmV116Num(state.money,0) + fee;
      state.finance = state.finance || {};
      state.finance.incomeTransfers = hfmV116Num(state.finance.incomeTransfers,0) + fee;
      news.resolved = true; news.requires_action = false;
      alert(`${p.name} wird an ${news.data.BUYER} verliehen. Leihgebuehr: ${euro(fee)}.`);
      if (typeof initLineup === 'function') initLineup();
      render();
      return false;
    }
  }
  return hfmV116ResolveNewsBase ? hfmV116ResolveNewsBase(id, action) : false;
};
window.hfmV68ResolveNewsAction = hfmV68ResolveNewsAction;

/* Sicherer Endloskalender: nach Saisonende sauber in die neue Saison, nie bei Dezember stoppen. */
function hfmV116SeasonBoundaryGuard() {
  try {
    const today = currentGameDate();
    const end = seasonEndDate();
    if (today && end && today > end && !state.seasonEndModal && !state.seasonStartModal) {
      state.seasonEndModal = typeof buildSeasonReview === 'function' ? buildSeasonReview() : { season: seasonLabel(), place: '-', points: '-', lastMatch: '-', squadAvg: avgStrength ? avgStrength() : '-', topPlayerName: '-', topPlayerStrength: '-', academyPlayers: (state.academyPlayers||[]).length, money: state.money, income: 0, expense: 0, saldo: 0, sponsorName: '-', };
      return true;
    }
    if (Number(state.week || 0) > 54 && !state.seasonEndModal && !state.seasonStartModal) {
      state.seasonEndModal = typeof buildSeasonReview === 'function' ? buildSeasonReview() : { season: seasonLabel() };
      return true;
    }
  } catch (err) { console.warn('Saison-Grenzpruefung fehlgeschlagen', err); }
  return false;
}
