HFM_V110_STAFF_ROLES.agent = { label: 'Spielerberater', slots: ['contacts','sales','clauses'], weights: { contacts: 0.45, sales: 0.35, clauses: 0.20 }, task: 'Aktive Spielerverkäufe, Vereinskontakte und Verkaufsklauseln' };
HFM_V110_STAFF_ATTR_LABELS.contacts = 'Vereinskontakte';
