const hfmV117ResolveNewsBase = hfmV68ResolveNewsAction;
hfmV68ResolveNewsAction = function(id, action) {
  const news = (state.newsItems || []).find(n => n.id === id);
  if (news && news.action_type === 'TRANSFER_OFFER' && action === 'accept' && news.data && Number(news.data.AGENT_PROVISION_PCT || 0) > 0) {
    const fee = Number(news.data.FEE_VALUE || 0);
    const pct = Number(news.data.AGENT_PROVISION_PCT || 0);
    const provision = Math.round(fee * pct / 100);
    const result = hfmV117ResolveNewsBase(id, action);
    state.money = Number(state.money || 0) - provision;
    state.finance = state.finance || {};
    state.finance.expenseTransfers = Number(state.finance.expenseTransfers || 0) + provision;
    hfmV68AddNews && hfmV68AddNews({ category: 'TRANSFER', priority: 2, scope: 'inbox', uniqueKey: `agent-provision-${id}`, title_template: 'Spielerberater-Provision gezahlt', body_template: `Für den Verkauf wurde eine Provision von ${euro(provision)} (${pct}%) abgezogen.`, data: {} });
    render();
    return result;
  }
  return hfmV117ResolveNewsBase ? hfmV117ResolveNewsBase(id, action) : false;
};
