const hfmV119OpenTransferNegotiationBase = hfmV108OpenTransferNegotiation;
hfmV108OpenTransferNegotiation = function(playerId, clubName, leagueIndex = OWN_LEAGUE_INDEX, options = {}) {
  const before = state.transferNegotiation;
  const ret = hfmV119OpenTransferNegotiationBase(playerId, clubName, leagueIndex, options || {});
  if (options && options.agentBuy && state.transferNegotiation) {
    state.transferNegotiation.agentCommissionPct = Number(options.agentCommissionPct || 0);
    state.transferNegotiation.agentSearchResultId = options.agentSearchResultId || '';
    state.transferNegotiation.lastMessage = `${state.transferNegotiation.lastMessage || ''} Hinweis: Bei erfolgreichem Kauf ueber den Spielerberater fallen zusaetzlich ${state.transferNegotiation.agentCommissionPct}% Provision auf die Ablöse an.`;
  }
  return ret;
};
