const hfmV119CommitTransferBase = hfmV108CommitTransfer;
hfmV108CommitTransfer = function(player, offer, neg) {
  const pct = Number(neg && neg.agentCommissionPct || 0);
  const fee = Number(neg && (neg.agreedFee || offer?.fee) || 0);
  const provision = pct > 0 ? Math.round(fee * pct / 100) : 0;
  if (provision > 0 && Number(state.money || 0) < fee + Number(offer?.bonus || 0) + provision) {
    alert(`Nicht genug Geld. Zusaetzlich zur Ablöse fällt Spielerberater-Provision an: ${euro(provision)}.`);
    return false;
  }
  const ok = hfmV119CommitTransferBase(player, offer, neg);
  if (ok && provision > 0) {
    state.money = Number(state.money || 0) - provision;
    state.finance = state.finance || {};
    state.finance.expenseTransfers = Number(state.finance.expenseTransfers || 0) + provision;
    if (typeof hfmV68AddNews === 'function') hfmV68AddNews({ category: 'TRANSFER', priority: 2, scope: 'inbox', uniqueKey: `buyer-agent-provision-${Date.now()}`, title_template: 'Provision an Spielerberater gezahlt', body_template: `Für den Kontakt zu ${player.name} wurden ${euro(provision)} Provision (${pct}% der Ablöse) gezahlt.`, data: {} });
    if (neg && neg.agentSearchResultId) {
      state.playerAgentSearchResults = (state.playerAgentSearchResults || []).map(r => String(r.id) === String(neg.agentSearchResultId) ? { ...r, players: (r.players || []).filter(p => String(p.id) !== String(player.id)) } : r);
    }
  }
  return ok;
};
window.hfmV108CommitTransfer = hfmV108CommitTransfer;

