function hfmV125TrainingMultiplier(player) {
  let mult = 1;
  if (hfmV125HasManagerTrait('TRAINING_EXPERT') && !(player && player.youth)) mult *= 1.05;
  if (hfmV125HasManagerTrait('YOUTH_DEVELOPER') && (player && (player.youth || Number(player.age || 99) <= 19))) mult *= 1.10;
  return mult;
}
const hfmV125CalcDevelopmentBase = calcDevelopment;
calcDevelopment = function(player, focus) {
  return Math.max(0, Math.round(hfmV125CalcDevelopmentBase(player, focus) * hfmV125TrainingMultiplier(player) * 10) / 10);
};
