const hfmV125DevelopAcademyBase = developAcademyPlayers;
developAcademyPlayers = function(focus) {
  const before = (state.academyPlayers || []).map(p => ({ id:p.id, progress:Number(p.progress || 0), strength:Number(p.strength || 0) }));
  hfmV125DevelopAcademyBase(focus);
  if (hfmV125HasManagerTrait('YOUTH_DEVELOPER')) {
    state.academyPlayers = (state.academyPlayers || []).map(p => {
      const old = before.find(b => b.id === p.id);
      if (!old) return p;
      const gained = (Number(p.progress || 0) - old.progress) + Math.max(0, Number(p.strength || 0) - old.strength) * 100;
      if (gained <= 0) return p;
      let progress = Number(p.progress || 0) + gained * 0.10;
      let updated = p;
      while (progress >= 100 && Number(updated.strength || 0) < 100) { updated = hfmV125ImprovePlayerSkillsBase(updated, 1); progress -= 100; }
      return { ...updated, progress: Math.round(progress) };
    });
  }
};
