const hfmV127PlayerProfileBase = playerProfileModal;
playerProfileModal = function(){
  const html = hfmV127PlayerProfileBase();
  const p = state.playerProfile;
  if (!html || !p) return html;
  const statusBits = [];
  if (p.injury) statusBits.push(`<article class="card"><p>Verletzung</p><h2>${hfmV127Html(p.injury.name)}</h2><span>noch ca. ${Number(p.injury.days || 0)} Tage · ${hfmV127Html(p.injury.cause || '')}</span></article>`);
  if (p.suspended || p.suspensionGames) statusBits.push(`<article class="card"><p>Sperre</p><h2>${Number(p.suspensionGames || 0)} Spiel(e)</h2><span>${Number(p.yellowCardsSeason || 0)} Gelbe · ${Number(p.redCardsSeason || 0)} Rote</span></article>`);
  if (!statusBits.length) statusBits.push(`<article class="card"><p>Karten/Sperren</p><h2>${Number(p.yellowCardsSeason || 0)} Gelbe</h2><span>${Number(p.redCardsSeason || 0)} Rote · spielberechtigt</span></article>`);
  return html.replace('</div>${known ? hfmV105ComfortBar', statusBits.join('') + '</div>${known ? hfmV105ComfortBar');
};
