    mk('stadium',{ name:'Stadion', icon:'🏟️', level:1, maxLevel:15, capacity:12000 });
    mk('training',{ name:'Trainingszentrum', icon:'💪', level:1, maxLevel:15 });
    mk('academy',{ name:'Akademie', icon:'🌱', level:1, maxLevel:15 });
    mk('youthCenter',{ name:'Jugendzentrum', icon:'👶', level:1, maxLevel:15 });
    mk('medical',{ name:'Medizin', icon:'🩺', level:1, maxLevel:15 });
