    const value = type === 'stadium' ? `${Number(f.capacity || 0).toLocaleString('de-AT')} Plätze · Level ${Number(f.level||1)}/${Number(f.maxLevel||15)}` : `Level ${Number(f.level||1)}/${Number(f.maxLevel||15)}`;
    const status = typeof upgradeStatus === 'function' ? upgradeStatus(type) : cfg.benefit(f.level||1);
