/* v144: Aufstellungs-Drag ohne kurzes Flackern und ohne unbeabsichtigten Klick nach dem Verschieben */
(function(){
  function v144Now(){ return Date.now ? Date.now() : new Date().getTime(); }
  function v144Root(){ return document.documentElement || document.body; }
  function v144NoFlicker(ms){
    try {
      const root = v144Root();
      root.classList.add('hfmSquadDragNoFlicker');
      window.__hfmV144NoFlickerUntil = v144Now() + (ms || 650);
      if (window.__hfmV144NoFlickerTimer) clearTimeout(window.__hfmV144NoFlickerTimer);
      window.__hfmV144NoFlickerTimer = setTimeout(function(){
        if (!window.__hfmV144NoFlickerUntil || v144Now() >= window.__hfmV144NoFlickerUntil) root.classList.remove('hfmSquadDragNoFlicker');
      }, ms || 650);
    } catch(e) {}
  }
  function v144KeepScroll(x, y){
    try { window.scrollTo(x, y); } catch(e) {}
    try { requestAnimationFrame(function(){ window.scrollTo(x, y); }); } catch(e) {}
  }
  function v144MarkDragging(el){
    try { if (el && el.classList) el.classList.add('hfmSquadDraggingSource'); } catch(e) {}
  }
  function v144ClearDragging(){
    try { document.querySelectorAll('.hfmSquadDraggingSource').forEach(function(el){ el.classList.remove('hfmSquadDraggingSource'); }); } catch(e) {}
  }
  function v144TransparentDragImage(event){
    try {
      if (!event || !event.dataTransfer) return;
      if (!window.__hfmV144DragImage) {
        const img = new Image();
        img.src = 'data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///ywAAAAAAQABAAACAUwAOw==';
        window.__hfmV144DragImage = img;
      }
      event.dataTransfer.setDragImage(window.__hfmV144DragImage, 0, 0);
    } catch(e) {}
  }
  function v144SuppressClick(ms){
    window.__hfmV144SuppressClickUntil = v144Now() + (ms || 700);
  }
  function v144ClickSuppressed(){
    return !!window.__hfmV144SuppressClickUntil && v144Now() < window.__hfmV144SuppressClickUntil;
  }
  function v144AfterRenderPolish(){
    try {
      if (window.__hfmV144NoFlickerUntil && v144Now() < window.__hfmV144NoFlickerUntil) {
        document.querySelectorAll('main.pageTransition').forEach(function(main){ main.classList.add('noPageTransition'); });
      }
    } catch(e) {}
  }

  const v144SquadDragStartBase = typeof squadDragStart === 'function' ? squadDragStart : null;
  if (v144SquadDragStartBase) {
    window.squadDragStart = squadDragStart = function(event, sourceType, sourceSlotId){
      v144NoFlicker(900);
      v144SuppressClick(900);
      v144MarkDragging(event && event.currentTarget ? event.currentTarget : null);
      const out = v144SquadDragStartBase(event, sourceType, sourceSlotId);
      v144TransparentDragImage(event);
      return out;
    };
  }

  const v144DropSquadPlayerBase = typeof dropSquadPlayer === 'function' ? dropSquadPlayer : null;
  if (v144DropSquadPlayerBase) {
    window.dropSquadPlayer = dropSquadPlayer = function(event, targetType, targetSlotId){
      const x = window.scrollX || window.pageXOffset || 0;
      const y = window.scrollY || window.pageYOffset || 0;
      v144NoFlicker(900);
      v144SuppressClick(900);
      let out;
      try { out = v144DropSquadPlayerBase(event, targetType, targetSlotId); }
      finally {
        v144ClearDragging();
        v144AfterRenderPolish();
        v144KeepScroll(x, y);
      }
      return out;
    };
  }

  const v144RenderBase = typeof render === 'function' ? render : null;
  if (v144RenderBase) {
    window.render = render = function(){
      const keep = !!(window.__hfmV144NoFlickerUntil && v144Now() < window.__hfmV144NoFlickerUntil);
      const x = window.scrollX || window.pageXOffset || 0;
      const y = window.scrollY || window.pageYOffset || 0;
      const out = v144RenderBase();
      v144AfterRenderPolish();
      if (keep) v144KeepScroll(x, y);
      return out;
    };
  }

  const v144OpenOwnProfileBase = typeof openOwnPlayerProfile === 'function' ? openOwnPlayerProfile : null;
  if (v144OpenOwnProfileBase) {
    window.openOwnPlayerProfile = openOwnPlayerProfile = function(id){
      if (v144ClickSuppressed()) return false;
      return v144OpenOwnProfileBase(id);
    };
  }
  const v144RosterClickBase = typeof hfmV88OpenOwnPlayerProfileFromRow === 'function' ? hfmV88OpenOwnPlayerProfileFromRow : null;
  if (v144RosterClickBase) {
    window.hfmV88OpenOwnPlayerProfileFromRow = hfmV88OpenOwnPlayerProfileFromRow = function(event, id){
      if (v144ClickSuppressed()) {
        if (event) { event.preventDefault(); event.stopPropagation(); }
        return false;
      }
      return v144RosterClickBase(event, id);
    };
  }

  document.addEventListener('dragend', function(){ v144ClearDragging(); v144NoFlicker(250); }, true);
  document.addEventListener('drop', function(){ v144ClearDragging(); v144SuppressClick(600); }, true);
  try { v144AfterRenderPolish(); } catch(e) {}
})();

/* === v154: Saisons -> Anstehende Bewerbe nur schrittweise anzeigen === */
(function(){
  function esc(v){
    try { if (typeof hfmV68Html === 'function') return hfmV68Html(v); } catch(e) {}
    return String(v ?? '').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  }
  function dateFromIso(iso){
    try { if (typeof hfmV117IsoToDate === 'function') return hfmV117IsoToDate(iso); } catch(e) {}
    const parts = String(iso || '').split('-').map(Number);
    return new Date(parts[0] || 2026, (parts[1] || 1) - 1, parts[2] || 1);
  }
  function fmtDate(d){
    try { return formatGermanDate(d); } catch(e) { return new Date(d).toLocaleDateString('de-DE'); }
  }
  function ownName(){
    try { return ownClubName(); } catch(e) { return state.clubName || 'Eigener Verein'; }
  }
  function upcomingCompetitionMatches(){
    const today = (typeof currentGameDate === 'function') ? currentGameDate() : new Date();
    const own = ownName();
    try {
      const idx = Number(state.startLeagueIndex ?? (typeof OWN_LEAGUE_INDEX !== 'undefined' ? OWN_LEAGUE_INDEX : 10));
      const pack = typeof hfmV117EnsureLeagueFixtures === 'function' ? hfmV117EnsureLeagueFixtures(idx) : null;
      if (pack && Array.isArray(pack.matches)) {
        return pack.matches
          .filter(m => m && (m.home === own || m.away === own))
          .filter(m => dateFromIso(m.date) >= today)
          .sort((a,b) => dateFromIso(a.date) - dateFromIso(b.date))
          .map(m => ({
            matchday: m.matchday,
            date: dateFromIso(m.date),
            home: m.home,
            away: m.away,
            place: m.home === own ? 'Heim' : 'Auswärts',
            source: pack.source || m.source || 'Spielkalender'
          }));
      }
    } catch(e) { console.warn('v154 fixtures fallback', e); }
    try {
      return (typeof calendarFixtures === 'function' ? calendarFixtures() : [])
        .filter(m => m && m.date >= today)
        .sort((a,b) => a.date - b.date)
        .map((m, i) => ({ matchday: i + 1, date: m.date, home: m.title || '', away: '', place: m.kind || '', source: 'Kalender' }));
    } catch(e) { return []; }
  }
  window.hfmV154MoreUpcomingCompetitions = function(){
    state.seasonCompetitionVisibleCount = Math.max(5, Number(state.seasonCompetitionVisibleCount || 5)) + 5;
    if (typeof hfmV77SilentSave === 'function') { try { hfmV77SilentSave(); } catch(e) {} }
    render();
    return false;
  };
  const setSeasonSectionBase = typeof setSeasonSection === 'function' ? setSeasonSection : null;
  window.setSeasonSection = setSeasonSection = function(section){
    if (section === 'schedule') state.seasonCompetitionVisibleCount = 5;
    if (setSeasonSectionBase) return setSeasonSectionBase(section);
    state.seasonSection = section;
    render();
    return false;
  };
  window.scheduleView = scheduleView = function(){
    const all = upcomingCompetitionMatches();
    const visibleCount = Math.max(5, Number(state.seasonCompetitionVisibleCount || 5));
    state.seasonCompetitionVisibleCount = visibleCount;
    const shown = all.slice(0, visibleCount);
    const next = shown[0] || all[0] || null;
    const nextBox = next ? `<div class="infoBox"><b>Nächstes Bewerbungsspiel:</b> ${esc(next.home)}${next.away ? ` - ${esc(next.away)}` : ''}<br>${fmtDate(next.date)}${next.matchday ? ` · Spieltag ${esc(next.matchday)}` : ''}<br><small>Quelle: ${esc(next.source || 'Spielkalender')}.</small></div>` : '<div class="infoBox">Aktuell sind keine anstehenden Bewerbungsspiele vorhanden.</div>';
    const rows = shown.map(m => `<tr><td>${esc(m.matchday || '-')}</td><td>${fmtDate(m.date)}</td><td><strong>${esc(m.home)}</strong>${m.away ? ` - ${esc(m.away)}` : ''}</td><td>${esc(m.place || '')}</td></tr>`).join('');
    const moreButton = all.length > shown.length ? `<button type="button" class="ghost full" onclick="return hfmV154MoreUpcomingCompetitions()">Mehr anzeigen</button>` : '';
    const countInfo = all.length > 0 ? `<div class="infoBox subtleInfo">Angezeigt: ${shown.length} von ${all.length} anstehenden Bewerbungsspielen.</div>` : '';
    return `<section class="panel widePanel"><p class="eyebrow">Saison · Anstehende Bewerbe</p><h2>Anstehende Bewerbe</h2>${nextBox}<div class="tableWrap"><table><thead><tr><th>ST</th><th>Datum</th><th>Partie</th><th>Ort</th></tr></thead><tbody>${rows || '<tr><td colspan="4">Noch keine Spiele erstellt.</td></tr>'}</tbody></table></div>${moreButton}${countInfo}</section>`;
  };
})();

