      const selectedPlayer = (state.players || []).find(p => Number(p.id) === Number(selectedId));
      const fit = typeof positionFit === 'function' ? positionFit(selectedPlayer, slot.pos) : { className:'' };
      const eff = selectedPlayer && typeof effectiveStrength === 'function' ? effectiveStrength(selectedPlayer, slot.pos) : 0;
